LOCK TABLES `design_goal` WRITE;
/*!40000 ALTER TABLE `design_goal` DISABLE KEYS */;
INSERT INTO `design_goal` VALUES (1,'Mobile-first & Accessible','It should be easy to play Poppy Seed Pets no matter who you are, or what kind of device you\'re using. If a choice _has_ to be made between making the game easy to play on a phone vs on a desktop/laptop computer, phone should win the day.'),(2,'Ad-free','I just personally hate ads with a passion more fiery than even [a Fierierstone](/poppyopedia/item/Fierierstone).'),(3,'Easy to Develop','There\'s only one human working on Poppy Seed Pets: me! If Poppy Seed Pets is going to continue to grow, I need to maximize the amount of time I can spend actively developing it, and avoid doing anything that would make working on the game slow/tedious/annoying/boring, etc.'),(4,'Not Too Expensive to Maintain','Poppy Seed Pets doesn\'t make any money; it costs money. I try to think of that cost as being instead of subscribing to a bajillion TV streaming services: I _could_ spend my money and time watching TV, but I\'d rather spend it making Poppy Seed Pets. Of course, there\'s a limit to how much I can spend this way, so costs need to be kept low.'),(5,'Cute & Nerdy','I started this game because I wanted to simulate Maslow\'s Hierarchy of Needs, and in doing so accidentally created a cute & nerdy game filled with affection, love, sci-fi, magic, and mythology! That cuteness & nerdiness is what drew people to the game in the first place, so it\'s something I want to be intentional about going forward!'),(6,'Emergent Gameplay & Goal-setting','Poppy Seed Pets is a kind of \"sims\" game: players set their own goals, and should be able to work towards those goals by exploring the mechanics of the game, and using them in clever ways. The more ways there are for a player to reach their goals, the better.'),(7,'Alone, but Together','Other design constraints require Poppy Seed Pets to be a relatively single-player experience (there aren\'t forums, for example). But social aspects add a lot to games: it\'s fun to be able to talk to other players about a shared experience.\r\n\r\nThis design goal is a reminder to myself to \"fight\" the naturally-single-player nature of Poppy Seed Pets, by adding social interactions where possible.'),(8,'Made with Help from Players','I\'m the only developer for Poppy Seed Pets, and I don\'t believe that one single brain is capable of coming up with great ideas all on its own. Involving players can not only be fun for those players, but interacting with players motivates me, and more brains means more good ideas.');
/*!40000 ALTER TABLE `design_goal` ENABLE KEYS */;
UNLOCK TABLES;

