/*!40000 ALTER TABLE `dream` DISABLE KEYS */;
INSERT INTO `dream` VALUES (1,'In a dream, %dreamer% was %wandering% %location1%, when they spotted %a_pet_or_monster%. It whispered something, but %dreamer% can\'t remember what, and gave %dreamer% %item%.','%A_pet_or_monster% gave this to %dreamer% in a dream.'),(2,'While %wandering% %location1% in a dream, %dreamer% spotted %item%. They reached down and grabbed it, and when they looked up, they were %location2%.','%dreamer% found this in %location1% in a dream.'),(3,'%dreamer% dreamed they tripped over %item%, and tumbled into a pit %location1%. The %item% fell in, too, and %dreamer% grabbed it, and ate it.','%dreamer% ate this while falling in a dream.'),(4,'In a dream, %dreamer% and a friend were %wandering% %location1%. The friend reached into their pocket and pulled out something covered in cloth. %dreamer% lifted up the cloth, and found %item%. When they looked up, their friend was gone.','%dreamer% received this from a friend in a dream.'),(5,'%dreamer% dreamed that they were making out with %a_species% on %surface% %location1%. %Item_with_article% got in the way, so %dreamer% tossed it aside.','%dreamer%, um, found this in a dream.'),(6,'In a dream, %dreamer% got in a fight with %a_species% %location1%. The %species% threw %item% at %dreamer%, and declared victory! >:(','A stupid %species% threw this at %dreamer% in a dream.'),(7,'In a dream, %dreamer% and a friend went out to eat, and ordered %item_with_article% and %a_food_or_drink%. When the %item% arrived, it was %more% than expected!','%dreamer% ordered this at a restaurant in a dream.'),(8,'%dreamer% saw their parents in a dream, but couldn\'t make them out. They hummed a familiar tune, and handed %dreamer% %item%.','%dreamer% got this from their parents in a dream.'),(9,'In a dream, %dreamer% found a secret compartment %location1%. They crawled inside, and arrived %location2%. On %surface%, there was %item%. %dreamer% took it.','%dreamer% found this on %surface% %location2% in a dream.'),(10,'In a dream, %dreamer% bumped into %a_pet_or_monster%, causing them to drop %item_with_article%. %dreamer% %adverb% picked it up, and tried to call out, but their voice wasn\'t working.','%dreamer% %adverb% picked this up in a dream.'),(11,'In a dream, %dreamer% was approached by a huge %item%. They %adverb% ran away; as they did so, the %item% shrank. Eventually, %dreamer% stopped, and picked it up.','%dreamer% was chased by this in a dream. (It was bigger in the dream...)'),(12,'%Location1% in a dream, %dreamer% looked in a mirror. They were %more% than usual. Also, there was %item_with_article% on their head!','%dreamer% saw this on their head while looking in a mirror in a dream.'),(13,'In a dream, %dreamer% was %wandering% %location1%, and found themselves %location2%, surrounded by %plural_stuff%! %dreamer% spotted %item% in the distance, reached out for it, then woke up.','%dreamer% found this amidst %plural_stuff% in a dream.'),(14,'In a dream, %dreamer% was in a room full of %plural_stuff%, kissing %a_species%, but the %species% was actually %item_with_article%? Or something? And then they woke up...','%dreamer% was kissing this in a dream?? (Don\'t ask; dreams are weird.)'),(15,'%dreamer% thought they were exploring %location1% in a dream, but they were actually %a_monster%, but super-tiny, exploring %surface%. They found %item_with_article% while wandering around (it was also super-tiny), and woke up.','%dreamer% found this on %surface% in a dream.'),(16,'%dreamer% got lost in a maze full of %plural_stuff% in a dream. They wandered around for what felt like forever before finally finding the %item% they had been sent to find there. Then they woke up.','In a dream, %dreamer% was sent on a quest to find this... and succeeded!'),(17,'%dreamer% had a dream where they were %a_monster%, but also they could _see_ %the_monster%? And %the_monster% was holding %item_with_article%, which %dreamer% took, even though they already had it... it was weird.','%dreamer% took this from their self, in a dream, when they were %a_monster%.');
/*!40000 ALTER TABLE `dream` ENABLE KEYS */;
UNLOCK TABLES;

