INSERT INTO `hollow_earth_tile_card` VALUES (1,1,'Let\'s Begin','{\"buttonText\": \"Was that an Undertale reference?\", \"description\": \"You find a box of dice in a disparity of sizes.\", \"receiveItems\": [\"Glowing Four-sided Die\", \"Glowing Six-sided Die\", \"Glowing Eight-sided Die\"]}',0,'go',NULL),(2,1,'Manor Gates','{\"item\": \"Iron Key\", \"type\": \"payItem?\", \"ifPaid\": {\"buttonText\": \"(I\'ll miss you!)\", \"description\": \"Goodbye, Iron Key!\", \"changeDirection\": \"E\"}, \"description\": \"A huge, iron gate blocks passage to the east. Fortunately - as everyone knows - any iron gate can be unlocked with any Iron Key.\"}',1,'iron-key',NULL),(3,1,'Fork (the Choice Kind)','{\"type\": \"chooseOne\", \"buttons\": [\"← West\", \"East →\"], \"outcomes\": [{}, {\"buttonText\": \"(Have I heard that somewhere before?)\", \"description\": \"East... always to the east...\", \"changeDirection\": \"E\"}], \"description\": \"Which way will you go?\"}',1,'forked-path',NULL),(4,1,'Totally-safe Mine Cart Ride','{\"id\": 1, \"type\": \"moveTo\", \"buttonText\": \"Probably.\", \"description\": \"An old mine cart leads down the mountain. It\'s probably fine.\"}',2,'mine-cart',NULL),(5,12,'Friendly Fisherman','{\"id\": 1, \"type\": \"moveTo\", \"buttonText\": \"That was nice of them!\", \"description\": \"You meet an old fisherman at the end of the peninsula. %pet.name% watches them for a while. The fisherman, seeing %pet.name%\'s interest, offers a special fishing pail, and a free ride across the river, back toward the village.\", \"receiveItems\": \"Shiny Pail\"}',2,'friendly-fisherman',NULL),(6,1,'Inspiring View','{\"buttonText\": \"Oh, like, \\\"Inspired\\\", as in the status effect? Nice!\", \"description\": \"%pet.name% was inspired by the view of the rolling hills, red-roofed houses, and sparkling sea.\", \"statusEffect\": {\"status\": \"Inspired\", \"duration\": 480, \"maxDuration\": 480}}',0,'',NULL),(7,1,'Light at the End of the Tunnel','{\"id\": 36, \"type\": \"moveTo\", \"buttonText\": \"Let\'s goooooo!\", \"description\": \"The light at the end of the tunnel! You rush forwards...\"}',0,'tunnel-end',NULL),(8,1,'A Narrow Side-passage','{\"type\": \"chooseOne\", \"buttons\": [\"Take it.\", \"Don\'t.\"], \"outcomes\": [{\"id\": 32, \"type\": \"moveTo\", \"buttonText\": \"Sure.\", \"description\": \"You squeeze through slick rocks, and under dripping stalactites...\"}, {}], \"description\": \"%pet.name% spots a shortcut: a narrow side-passage...\"}',0,'',NULL),(10,1,'River Rafting','{\"type\": \"chooseOne\", \"buttons\": [\"Take it.\", \"Don\'t.\"], \"outcomes\": [{\"id\": 48, \"type\": \"moveTo\", \"buttonText\": \"What now?\", \"description\": \"You push the raft onto the river, and hop on. The river begins to pick up speed, and you eventually hop off.\"}, {}], \"description\": \"%pet.name% spots a shortcut: a small raft on the river bank.\"}',0,'raft',NULL),(11,1,'Hilltop Zone','{\"esteem\": 4, \"safety\": 4, \"description\": \"%pet.name% had a peaceful rest in the breeze atop a small hill.\"}',0,'',NULL),(12,1,'Almost There','{\"type\": \"chooseOne\", \"buttons\": [\"Go back one space.\", \"Go forward one space.\", \"Go forward two, and see what\'s at the end!\"], \"outcomes\": [{\"id\": 49, \"type\": \"moveTo\", \"buttonText\": \"Sometimes life be like that.\", \"description\": \"One step forward, two steps backwards.\"}, {\"id\": 51, \"type\": \"moveTo\", \"buttonText\": \"Nice.\", \"description\": \"A leisurely stroll, it is.\"}, {\"id\": 52, \"type\": \"moveTo\", \"description\": \"I get that.\"}], \"description\": \"Decisions, decisions...\"}',0,'almost-there',NULL),(13,2,'25 Big Ones','{\"buttonText\": \"Woo!\", \"description\": \"25~~m~~ are just lying on the ground here?? Must have been dropped by one of those horrible, Raucous Goblins that lurk around here.\", \"receiveMoneys\": 25}',0,'25m',NULL),(14,3,'Raucous Goblin','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": -2, \"safety\": -2, \"description\": \"The Goblin smacks %pet.name% on the head, then runs into the hills, laughing.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": 2, \"safety\": 2, \"description\": \"%pet.name% grabs the Crooked Stick and yanks it from the Goblin\'s hands; the Goblin, apparently not expecting this, looks horrified, and runs screaming into the hills, dropping a Paper Bag on its way.\", \"receiveItems\": [\"Crooked Stick\", \"Paper Bag\"]}, \"buttonText\": \"Defend yourself!\", \"description\": \"A Raucous Goblin jumps out from behind a rock and waves a stick threateningly.\", \"requiredRoll\": 10}',0,'noisy-goblin',NULL),(15,2,'Suspicious Flower Basket','{\"type\": \"onward\", \"buttonText\": \"Aw, that\'s nice!\", \"description\": \"There\'s a Flower Basket placed so precisely in the middle of the road, there is no mistaking that whoever placed it there did so with some clear purpose in mind. It doesn\'t appear to be trapped, though... did someone just want to give this to you? Or %pet.name%?\\n\\nWell, may as well take it, then! Thank you, mysterious flower benefactor!\", \"receiveItems\": \"Flower Basket\"}',0,'flower-basket',NULL),(16,3,'Inspiring Valley','{\"description\": \"You stopped for a while in a lush valley; %pet.name% was inspired by its natural beauty.\", \"statusEffect\": {\"status\": \"Inspired\", \"duration\": 480, \"maxDuration\": 480}}',0,'eye',NULL),(17,6,'Private Fishing Spot','{\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"description\": \"%pet.name% stopped to do some fishing, and pulled up a couple Fish, some Scales, and a translucent egg...\", \"receiveItems\": [\"Fish\", \"Fish\", \"Scales\", \"Mermaid Egg\"]}',0,'manor-fishing',NULL),(18,6,'Cellar Door','{\"type\": \"petChallenge\", \"stats\": [\"intelligence\", \"crafts\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"crafts\"], \"amount\": 1}, \"esteem\": -2, \"buttonText\": \"We\'ll get you next time, lock!\", \"description\": \"%pet.name% wasn\'t able to pick the cellar door lock. A lot of dust and Fluff was kicked up, though, so %pet.name% took some of that.\", \"receiveItems\": [\"Fluff\", \"Fluff\", \"Fluff\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"crafts\"], \"amount\": 1}, \"esteem\": 2, \"buttonText\": \"Neat-o.\", \"description\": \"%pet.name% picked the cellar door lock successfully, and found some Blackberry Wine, several mushrooms, and a Little Strongbox!\", \"receiveItems\": [\"Little Strongbox\", \"Blackberry Wine\", \"Chanterelle\", \"Chanterelle\", \"Toadstool\"]}, \"buttonText\": \"Lock-pickin\' time!\", \"description\": \"%pet.name% decides to explore an abandoned house, and finds a locked cellar door...\", \"requiredRoll\": 13}',0,'cellar-door',NULL),(19,6,'Run-down Orchard','{\"buttonText\": \"Delic\'!\", \"description\": \"Outside an abandoned house, %pet.name% found a run-down orchard & vineyard still producing fruit. %pet.name% grabbed as much as they could.\", \"receiveItems\": [\"Orange\", \"Yellowy Lime\", \"Red\", \"Apricot\", \"Blackberries\", \"Crooked Stick\", \"Avocado\", \"Bag of Fertilizer\", \"Twilight Fertilizer\"]}',0,'orchard',NULL),(20,6,'Attic Box Box','{\"buttonText\": \"Cool.\", \"description\": \"%pet.name% explored the attic of an abandoned house, and found a Box Box.\", \"receiveItems\": \"Box Box\"}',0,'attic-box-box',NULL),(21,3,'Limestone Golem','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"stamina\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": -2, \"description\": \"After a long battle of neither being able to harm the other, %pet.name% eventually gives up trying to defeat the golem, and just runs around the slow thing.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 3}, \"esteem\": 3, \"safety\": 3, \"description\": \"After a long fight, of neither being able the harm the other, %pet.name% manages to chip a block of Limestone off the golem. Apparently defeated, the golem stomps away into the hills.\", \"receiveItems\": \"Limestone\"}, \"buttonText\": \"A limestone golem? That\'s awfully specific...\", \"description\": \"A large golem made of limestone blocks the path...\", \"requiredRoll\": 15}',0,'limestone-golem',NULL),(22,4,'Flock of Thieving Magpies','{\"type\": \"petChallenge\", \"stats\": [\"intelligence\", \"nature\", \"stealth\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\", \"stealth\"], \"amount\": 1}, \"buttonText\": \"Good enough, I suppose.\", \"description\": \"Mistaking a flock of Thieving Magpies for common robins, %pet.name% searched for robin nests nearby. They found one, anyway, and got a couple Eggs, and a Crooked Branch.\", \"receiveItems\": [\"Egg\", \"Egg\", \"Crooked Stick\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\", \"stealth\"], \"amount\": 3}, \"esteem\": 3, \"description\": \"%pet.name% noticed a flock of Thieving Magpies flying overhead, and realized they must be leaving their nest, so they looked for the birds\' cache... and found it! (Cha-ching!)\", \"receiveItems\": [\"Gold Bar\", \"\\\"Gold\\\" Idol\", \"Sand Dollar\"]}, \"buttonText\": \"Take a look.\", \"description\": \"A flock of birds flew overhead...\", \"requiredRoll\": 15}',0,'magpies',NULL),(23,5,'Holey Shirt','{\"item\": \"White Cloth\", \"type\": \"payItem?\", \"ifPaid\": {\"description\": \"The kid thanks you, hands over a Glowing Four-sided Die, and resumes sewing.\", \"receiveItems\": \"Glowing Four-sided Die\"}, \"buttonText\": \"Thanks, kid.\", \"description\": \"A young villager is sitting on a log, sewing a hole in their shirt. Upon spotting you, the villager asks for a bit of White Cloth, offering a die in return.\"}',0,'holey-shirt',NULL),(24,5,'Disheveled Bard','{\"type\": \"petChallenge\", \"stats\": [\"music\"], \"ifFail\": {\"exp\": {\"stats\": [\"music\"], \"amount\": 1}, \"esteem\": -2, \"description\": \"%pet.name% tried to help a bard tune his instrument; after a while of trying, the bard politely turned %pet.name% away...\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"music\"], \"amount\": 1}, \"esteem\": 2, \"description\": \"%pet.name% helped a disheveled bard tune his instrument (and got a Music Note in the process). Grateful, the bard also gave %pet.name% an odd scrap of paper that looked like a piece of a map!\", \"receiveItems\": [\"Music Note\", \"Piece of Cetgueli\'s Map\"]}, \"buttonText\": \"Offer help.\", \"description\": \"A bard on the side of the road was tuning his instrument - a curious implement looking approximately like a lute, and precisely as out-of-sorts as its owner.\", \"requiredRoll\": 10}',0,'lute',NULL),(25,5,'Blacksmith\'s Shop','{\"type\": \"payMoneys?\", \"amount\": 10, \"ifPaid\": {\"description\": \"\\\"Here you are. Good luck in your travels!\\\"\", \"receiveItems\": \"Iron Bar\"}, \"description\": \"There\'s a blacksmith\'s shop, selling Iron Bars for 10~~m~~.\"}',1,'blacksmith',NULL),(26,5,'Jeweler\'s Workshop','{\"type\": \"payMoneys?\", \"amount\": 15, \"ifPaid\": {\"description\": \"\\\"Here you are. Thanks for coming in.\\\"\", \"receiveItems\": \"Silver Bar\"}, \"description\": \"There\'s a jeweler\'s workshop, selling Silver Bars for 15~~m~~.\"}',1,'jeweler',NULL),(27,2,'Exactly Three Fluff and One Note','{\"buttonText\": \"I\'ll take it. Well: the Fluff, anyway.\", \"description\": \"%pet.name% finds some bits of Fluff on the side of the road. And a note that reads \\\"combine three tongs:<br>M A X I M U M<br>t o n g s.\\\"\", \"receiveItems\": [\"Fluff\", \"Fluff\", \"Fluff\"]}',0,'maximum-tongs',NULL),(28,14,'An Oversized Goat','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": -2, \"safety\": -5, \"buttonText\": \"What a dick!\", \"description\": \"After a long battle of starts and feints, the goat finally gets a headbutt in and knocks %pet.name% to the ground. Apparently pleased with itself, the goat gallops up the mountain, showering you with gravel and dust.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 3}, \"esteem\": 3, \"safety\": 3, \"buttonText\": \"Stupid goats.\", \"description\": \"During an arduously-long fight, %pet.name% manages to chip a bit of the goat\'s horn off, and steal some of its Creamy Milk (best not to ask how). Offended, the goat gallops up the mountain, showering you with gravel and dust.\", \"receiveItems\": [\"Talon\", \"Talon\", \"Creamy Milk\", \"Creamy Milk\"]}, \"buttonText\": \"(This game has a lot goats, doesn\'t it?)\", \"description\": \"An oversized goat walks onto the path, and stares you down with its creepy, rectangle-pupiled eyes.\", \"requiredRoll\": 15}',0,'goat',NULL),(29,14,'Box of Ores','{\"buttonText\": \"Yes, yes, you\'re very clever. Thanks for the ore.\", \"description\": \"Outside an abandoned mine, %pet.name% noticed an equally-abandoned box of rocks! But they weren\'t rocks; they were rock lost ores!\", \"receiveItems\": \"Box of Ores\"}',0,'box-of-ores',NULL),(30,8,'Stereotypical Tile','{\"buttonText\": \"Just like in the movies.\", \"description\": \"Inside the cave, %pet.name% spots an old torch, and lights it.\", \"receiveItems\": \"Stereotypical Torch\"}',0,'torch',NULL),(31,8,'Cave-in','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"strength\"], \"ifFail\": {\"id\": 18, \"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"type\": \"moveTo\", \"buttonText\": \"Back we go...\", \"description\": \"Not wanting to be crushed by the cave-in, and seeing no other options, you run out of the cave.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"buttonText\": \"Phew!\", \"description\": \"%pet.name% spots a sheltering overhang, grabs you by your shirt, and jumps under it, barely avoiding a large boulder! It seems you\'re not the first to take refuge here, as there\'s a small sack of long-abandoned supplies. After the cave-in settles down, you pillage the sack, and continue your journey.\", \"receiveItems\": [\"White Cloth\", \"Fermented Fish\", \"Naner Preserves\"], \"receiveMoneys\": 10}, \"buttonText\": \"No one appreciates my humor...\", \"description\": \"You start to make a lewd joke about the impressively-sized stalagmites, but your echoing voice causes some kind of cave-in, cutting your joke short!\", \"requiredRoll\": 12}',0,'cave-in',NULL),(32,8,'Bat Matter','{\"esteem\": -3, \"safety\": -3, \"buttonText\": \"Neat! Let\'s scoop some up!\", \"description\": \"You accidentally disturb a colony of sleeping bats, sending them into a flying frenzy! Nothing bad happens, but it is a little scary. You wait on the ground for a couple minutes for the bats to fly elsewhere; while you\'re lying there, you see some bits of Dark Matter. It seems at least one of the bats has a Black-hole Tum!\", \"receiveItems\": \"Dark Matter\"}',0,'guano',NULL),(33,8,'Iron Vein','{\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"description\": \"%pet.name% stops to mine some iron.\", \"receiveItems\": [\"Iron Ore\", \"Iron Ore\"]}',0,'iron-vein',NULL),(34,8,'Gelatinous Rubes','{\"type\": \"petChallenge\", \"stats\": [\"dexterity\", \"brawl\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": 2, \"buttonText\": \"Disgusting creatures!\", \"description\": \"Gelatinous Rubes move pretty slowly, so after you both dodge its surprise attack, it really doesn\'t stand much chance. %pet.name% tried to steal some of the objects suspended inside it, but the slime burned a little, so eventually they gave up, and you both walked briskly away.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 2}, \"esteem\": 4, \"buttonText\": \"Success!\", \"description\": \"Gelatinous Rubes move pretty slowly, so after you both dodge its surprise attack, it really doesn\'t stand much chance. %pet.name% reached inside the creature and stole some objects which were suspended inside of it; then you both walked briskly away.\", \"receiveItems\": [\"Iron Key\", \"Rusty Rapier\"]}, \"buttonText\": \"How rude!\", \"description\": \"A Gelatinous Rube stretches down from the cave ceiling, in an attempt to embrace and dissolve you both!\", \"requiredRoll\": 15}',0,'jellies',NULL),(35,8,'Rockin\' Formations','{\"type\": \"onward\", \"esteem\": 4, \"safety\": 4, \"description\": \"%pet.name% admired the magnificent cave formations.\"}',1,'cave-formations',NULL),(36,10,'Ghost Fishing','{\"type\": \"petChallenge\", \"stats\": [\"nature\", \"dexterity\", \"umbra\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\", \"umbra\"], \"amount\": 1}, \"type\": \"onward\", \"description\": \"%pet.name% wasn\'t able to catch any of the ghost fish...\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\", \"umbra\"], \"amount\": 2}, \"type\": \"onward\", \"esteem\": 2, \"description\": \"%pet.name% hooks a few, and harvests their Quintessence. And also some Scales.\", \"receiveItems\": [\"Scales\", \"Quintessence\", \"Quintessence\", \"Quintessence\"]}, \"buttonText\": \"Let\'s go fishing!\", \"description\": \"%pet.name% spots a strange, underground lake with glowing fish in it... they\'re the spirits of deceased fish!\", \"requiredRoll\": 15}',0,'ghost-fish',NULL),(37,8,'Silver Vein','{\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"description\": \"%pet.name% stops to mine some silver.\", \"receiveItems\": [\"Silver Ore\", \"Silver Ore\"]}',0,'silver-vein',NULL),(38,1,'Lost in the Dark','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"intelligence\", \"nature\"], \"ifFail\": {\"id\": 26, \"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"type\": \"moveTo\", \"buttonText\": \"Easy mistake to make. These are dark caves.\", \"description\": \"%pet.name% is pretty sure that they took a wrong turn, and need to head back north... after passing a definitely-familiar-looking lake, however, they realize they should have kept going south, after all!\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"buttonText\": \"Crisis averted!\", \"description\": \"%pet.name% looks around for a little bit, and realizes that they\'re on the correct path after all.\"}, \"buttonText\": \"Are we going in circles?\", \"description\": \"Wait... that stalactite looks familiar.\", \"requiredRoll\": 12}',0,'lost-in-the-dark',NULL),(39,8,'Mixed Vein','{\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 3}, \"description\": \"%pet.name% stops to mine some iron, silver, and gold!\", \"receiveItems\": [\"Iron Ore\", \"Silver Ore\", \"Gold Ore\"]}',0,'mixed-vein',NULL),(40,8,'Hidden Alcove','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 2}, \"esteem\": -3, \"buttonText\": \"Defeated by a boulder :(\", \"description\": \"%pet.name% tried to move the boulder, but it was wedged firmly in place, and would not move.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 2}, \"esteem\": 3, \"buttonText\": \"Such strength!\", \"description\": \"%pet.name% heaved the huge rock aside, revealing a medium-sized alcove, which contained a Little Strongbox.\", \"receiveItems\": \"Little Strongbox\"}, \"buttonText\": \"There\'s gotta\' be!\", \"description\": \"%pet.name% spots an out-of-place boulder. There\'s gotta\' be something hiding behind there!\", \"requiredRoll\": 20}',0,'hidden-alcove',NULL),(41,13,'Bat \"Boss\"','{\"type\": \"chooseOne\", \"buttons\": [\"What?! The cave has a boss!?!\"], \"outcomes\": [{\"exp\": {\"stats\": [\"brawl\"], \"amount\": 5}, \"esteem\": 2, \"safety\": 2, \"buttonText\": \"What a lame boss!\", \"description\": \"The cave boss turned out to be a pushover. %pet.name% beat it up and took all its stuff. Which wasn\'t even that much? It was a pretty good workout, though, so that\'s something.\", \"receiveItems\": [\"Fluff\", \"Fluff\", \"Dark Matter\", \"Talon\"]}], \"description\": \"Oh no! It\'s the boss of the cave: a giant bat!\"}',0,'bat-boss',NULL),(42,9,'Gallant Gator','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 5}, \"esteem\": 4, \"buttonText\": \"Well fought!\", \"description\": \"%pet.name% and the gator fought for a while, but in the end, the gator won. The two gave each other acknowledging glances of respect, and went their separate ways.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 5}, \"esteem\": 5, \"buttonText\": \"Well fought!\", \"description\": \"%pet.name% and the gator fought for a while, and in the end, %pet.name% won. The two gave each other acknowledging glances of respect, and went their separate ways.\"}, \"buttonText\": \"Bring it, gator!\", \"description\": \"%pet.name%\'s locked eyes with a lurking gator. The gator made one of those \\\"bring it\\\" gestures with its right, um, paw? Claw? Foot? Whatever.\", \"requiredRoll\": 15}',0,'gator',NULL),(43,7,'Bridge Fishin\'','{\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"description\": \"%pet.name% stops to do some fishing on the bridge, and gets a couple Scales, a bit of Fish, and a piece of driftwood in the form of a Crooked Stick.\", \"receiveItems\": [\"Fish\", \"Scales\", \"Scales\", \"Crooked Stick\"]}',0,'bridge-fishing',NULL),(44,9,'Gone Fishing','{\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"description\": \"%pet.name% stops to do some fishing, and gets a couple Fish, and some Scales.\", \"receiveItems\": [\"Fish\", \"Fish\", \"Scales\"]}',0,'river-fishing',NULL),(45,7,'Shimmering Waterfall','{\"type\": \"onward\", \"esteem\": 4, \"safety\": 4, \"description\": \"%pet.name% admired the shimmering waterfall.\"}',1,'shimmering-waterfall',NULL),(46,2,'Broken Wagon','{\"type\": \"petChallenge\", \"stats\": [\"intelligence\", \"dexterity\", \"crafts\"], \"ifFail\": {\"exp\": {\"stats\": [\"crafts\"], \"amount\": 1}, \"esteem\": -2, \"description\": \"%pet.name% tried to help the settlers repair their wagon, but couldn\'t help. The settlers thanked %pet.name% anyway, and you continued on your way.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"crafts\"], \"amount\": 1}, \"esteem\": 2, \"description\": \"%pet.name% helped repair the settlers\' wagon. They offered some moneys and a small box of food as thanks.\", \"receiveItems\": \"Fruits & Veggies Box\", \"receiveMoneys\": 15}, \"buttonText\": \"The Hollow-earth Trail...?\", \"description\": \"You come across some settlers in a covered wagon on the side of the road. Their wagon\'s axle and tongue has broken. You didn\'t know wagons could have even have tongues, but %pet.name% thinks they know exactly what to do, and offers to help with repairs.\", \"requiredRoll\": 13}',0,'broken-wagon',NULL),(47,9,'Simply Squid','{\"description\": \"%pet.name% fishes up a medium-sized squid without any trouble whatsoever.\", \"receiveItems\": [\"Tentacle\", \"Tentacle\", \"Fish\", \"Green Dye\"]}',0,'squid',NULL),(48,1,'Sandstorm','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"intelligence\", \"nature\"], \"ifFail\": {\"id\": 41, \"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"type\": \"moveTo\", \"buttonText\": \"Cursed sands!\", \"description\": \"%pet.name% finally picks a direction, and you start walking. After a while, you spot a familiar-looking waterfall up ahead, and realize you\'ve gone the wrong way :|\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"buttonText\": \"Crisis averted!\", \"description\": \"%pet.name% looks around for a little bit. After some brief scouting, they figure out which direction south is, and you continue your journey, on-course.\"}, \"buttonText\": \"Let\'s look around...\", \"description\": \"A sandstorm swirls in from the west. After it clears, %pet.name% is unsure which direction they\'re facing...\", \"requiredRoll\": 12}',0,'sandstorm',NULL),(49,2,'Wild Herb & Vegetable Field','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"nature\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"esteem\": 2, \"buttonText\": \"Not bad, all things considered.\", \"description\": \"%pet.name% wasn\'t able to find much. One good-looking Onion. A Crooked Stick. And... some Toad Legs??\", \"receiveItems\": [\"Onion\", \"Crooked Stick\", \"Toad Legs\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"esteem\": 2, \"buttonText\": \"Nice!\", \"description\": \"%pet.name% found all kinds of wild fruits & veggies, and even some nice flowers!\", \"receiveItems\": [\"Onion\", \"Celery\", \"Bird\'s-foot Trefoil\", \"Rosemary\", \"Ginger\", \"Tomato\", \"Spicy Peps\"]}, \"buttonText\": \"Let\'s see what we can find!\", \"description\": \"You stumble upon a field of wild herbs and vegetables. %pet.name% starts looking for some good produce...\", \"requiredRoll\": 13}',0,'wild-garden',NULL),(50,11,'Natural Glass','{\"description\": \"%pet.name% explored the lightning-struck edges of a desert, finding a bunch of Silica Grounds, and a bit of Glass.\", \"receiveItems\": [\"Silica Grounds\", \"Silica Grounds\", \"Silica Grounds\", \"Glass\"]}',0,'desert-lightning',NULL),(51,2,'Preying Mantis','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"esteem\": -2, \"safety\": -5, \"buttonText\": \"I stand corrected.\", \"description\": \"Nope. _Preying_ mantis. It proves this point quite effectively via the point of its spear; %pet.name% tries to fight, but you\'re both forced to flee.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 3}, \"esteem\": 3, \"safety\": 3, \"buttonText\": \"Damn, son.\", \"description\": \"In this case, it is \\\"preying\\\", but maybe a life of prayer would have served this creature better: %pet.name% tore it limb from limb, claiming its Hunting Spear, and apparently a Minor Scroll of Riches!\", \"receiveItems\": [\"Hunting Spear\", \"Minor Scroll of Riches\"]}, \"buttonText\": \"Isn\'t that \\\"praying\\\" mantis?\", \"description\": \"A large, humanoid preying mantis strides out of the desert holding a spear, and prepares to attack!\", \"requiredRoll\": 15}',0,'preying-mantis',NULL),(52,2,'Mushroom Hunting','{\"type\": \"chooseOne\", \"buttons\": [\"Pick Chanterelles\", \"Pick Toadstools\"], \"outcomes\": [{\"love\": 4, \"description\": \"You spend some time harvesting Chanterelles together before continuing your journey.\", \"receiveItems\": [\"Chanterelle\", \"Chanterelle\", \"Chanterelle\", \"Chanterelle\", \"Chanterelle\"]}, {\"love\": 4, \"description\": \"You spend some time harvesting Toadstools together before continuing your journey.\", \"receiveItems\": [\"Toadstool\", \"Toadstool\", \"Toadstool\", \"Toadstool\", \"Toadstool\"]}], \"description\": \"You stumble upon a field of boulders, beneath which are large colonies of mushrooms!\"}',0,'mushrooms',NULL),(53,8,'Gold Vein','{\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"description\": \"%pet.name% stops to mine some gold.\", \"receiveItems\": [\"Gold Ore\", \"Gold Ore\"]}',0,'gold-vein',NULL),(54,13,'Giant Cave Toad','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 3}, \"esteem\": -2, \"safety\": -5, \"buttonText\": \"Such powerful legs!\", \"description\": \"%pet.name% charges the creature, but before they can get within hitting distance, the toad hops over them, sending a shower of rocks and dust onto %pet.name%\'s head. After the dust settles, the toad is nowhere to be seen...\", \"receiveItems\": [\"Rock\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 5}, \"esteem\": 3, \"safety\": 3, \"buttonText\": \"Where\'s your legs now, huh?!\", \"description\": \"%pet.name% charges the creature, which leaps over them, but as it\'s soaring overhead, %pet.name% reaches up, and grabs its legs, pulling them clean off! (The Toad Legs are so big, they count double!) The toad roars, and vanishes into the darkness of the tunnel behind you, trailing magic dust from its wounds...\", \"receiveItems\": [\"Toad Legs\", \"Toad Legs\", \"Quintessence\"]}, \"buttonText\": \"Goodness! It\'s a cave boss, for sure!\", \"description\": \"Near the end of the tunnel, %pet.name% sees the silhouette of a large toad with glowing eyes!\", \"requiredRoll\": 15}',0,'giant-toad',NULL),(55,8,'Blackonite Deposit','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"stamina\", \"nature\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"food\": -2, \"description\": \"You and %pet.name% spend some time trying to extract the Blackonite, but despite your best efforts, the Blackonite remains firmly stuck to the rock wall of the cave!\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 3}, \"food\": -2, \"buttonText\": \"Woo!\", \"description\": \"You and %pet.name% spend some time extracting the Blackonite from the rock wall of the cave. It\'s hard work, but hey: Blackonite!\", \"receiveItems\": [\"Blackonite\"]}, \"buttonText\": \"Let\'s get it!\", \"description\": \"You catch something gleaming in the darkness: a Blackonite deposit!\", \"requiredRoll\": 14}',0,'',NULL),(56,10,'Visions in the Water','{\"exp\": {\"stats\": [\"umbra\"], \"amount\": 3}, \"type\": \"onward\", \"buttonText\": \"Creepy! (But also educational!)\", \"description\": \"While passing the Underground Lake, %pet.name% sees visions of another world reflected in its surface...\"}',1,'',NULL),(58,5,'Bakery Bites','{\"buttonText\": \"Sweet! A Sweet Roll! Fresh from the oven!\", \"description\": \"%pet.name% stops to accept a free sample from a local bakery.\", \"receiveItems\": [\"Sweet Roll\"]}',0,'sweet-roll',NULL),(59,12,'Friendly Ferrywoman','{\"id\": 1, \"type\": \"moveTo\", \"buttonText\": \"So wholesome!\", \"description\": \"You see an old ferrywoman cursing at a magpie as it flies away, clutching a necklace. %pet.name% immediately gives chase, vanishing over the crest of a hill. You catch up eventually, and find %pet.name% glaring at a squawking magpie. The magpie flies off, and you spot the necklace - and a Fishkebab - at %pet.name%\'s feet! You pick up the necklace, and head back to the ferrywoman, spotting a Sand Dollar on the way! (Nice!)\\n\\nA bit of exercise, a Fishkebab, a Sand Dollar, and a happy ferrywoman! As good an end to an adventure as one could hope!\", \"receiveItems\": [\"Fishkebab\", \"Sand Dollar\"]}',2,'friendly-fisherwoman',NULL),(60,9,'Waterway Robbers','{\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"description\": \"As you\'re walking by the river, you spot a small group of raccoons fighting the guard of a merchant fish caravan! %pet.name% steps in to help, turning the tides in the fish\'s favor! One of the fish is wounded, so you offer to take them back through the portal, to your Tell Samarzhoustia merchant contact. They happily accept, promising handsome rewards upon their safe return!\", \"receiveItems\": [\"Merchant Fish\"]}',0,'raccoon',NULL),(61,5,'Melodimancer','{\"type\": \"payMoneys?\", \"amount\": 60, \"ifPaid\": {\"description\": \"\\\"Wonderful! Stop by anytime!\\\"\", \"receiveItems\": \"Scroll of Songs\"}, \"description\": \"You pass a Melodimancer\'s studio, selling Scrolls of Songs for 60~~m~~.\"}',1,'melodimancer',NULL),(62,5,'The Cosmologer','{\"item\": \"Meteorite\", \"type\": \"payItem?\", \"ifPaid\": {\"description\": \"The cosmologer leaps excitedly into the air. \\\"Wonderful!\\\" she exclaims, taking the rock, \\\"just wonderful!\\\"\\n\\nYou wait a moment.\\n\\n\\\"Ah, yes, I suppose I did promise you some payment, didn\'t I? Ah, let me see here...\\\" she looks around. \\\"Well, now is a bad time, you understand... but later! I promise! And I\'ll let you pick the reward, eh? Yes, yes, very good.\\\"\\n\\nShe waves her arms at nothing in particular, then returns to her desk.\\n\\n\\\"Now: what secrets are you hiding, little rock, hm? Haha! We\'ll soon find out!\\\"\\n\\n(You\'ve received a Cosmologer\'s Promise?)\", \"receiveItems\": \"Cosmologer\'s Promise\"}, \"ifNotPaid\": {\"description\": \"\\\"Damnable, sneaky rocks! They burn so brilliantly in the atmosphere, why not in the trees, or grass? WELL: if you wish to abandon the search, I understand. But my offer still stands, should you happen to find the thing.\\\"\\n\\nShe returns to her desk.\\n\\n\\\"Now where was I? Ah, yes...\\\"\"}, \"description\": \"You enter the lab of a cosmologer, setting off a small door bell.\\n\\n\\\"Hold on just one moment!\\\" she calls, shuffling through photos and scribbled notes on her work desk. \\\"Bah! Nothing.\\\"\\n\\nShe throws a photo onto the desk, giving it a slight spin. It slides off the other end, and falls to the floor, corner first, producing a soft, but audible \\\\*clack\\\\*.\\n\\nShe frowns, then stands up and turns to face you. Her frown turns into an excited grin.\\n\\n\\\"Oh! You\'re finally back! Perhaps my luck has turned! Were you able to find that Meteorite?\\\"\"}',0,'cosmologer',NULL),(63,8,'Everice Cream','{\"type\": \"petChallenge\", \"stats\": [\"perception\", \"nature\", \"crafts\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"esteem\": 2, \"buttonText\": \"It\'s something, at least!\", \"description\": \"Some of it melted; some of it didn\'t. %pet.name% came away with a piece of Everice, and some Creamy Milk.\", \"receiveItems\": [\"Everice\", \"Creamy Milk\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"esteem\": 2, \"buttonText\": \"Nice!\", \"description\": \"%pet.name% skillfully chiseled at the vein, extracting several samples of that tasty, tasty icèd cream!\", \"receiveItems\": [\"Honeydont Ice Cream\", \"Blueberry Ice Cream\", \"Naner Ice Cream\"]}, \"buttonText\": \"Strike the earth!\", \"description\": \"In a chilly corner of the cave, you spot a vein of icèd cream!\", \"requiredRoll\": 18}',0,'ice-cream-cone',NULL),(64,1,'Lost in Time and Space','{\"id\": -1, \"type\": \"moveTo\", \"buttonText\": \"Oh, dang!\", \"description\": \"Somehow, you got lost in time and space. The universe will surely find you again, though who knows where...\"}',1,'',NULL),(65,2,'Lost Lunch','{\"buttonText\": \"Free lunch!\", \"description\": \"There\'s a Paper Bag lying just off in the bushes. Someone must have lost their lunch!\", \"receiveItems\": [\"Paper Bag\"]}',0,'paper-bag',NULL),(66,5,'The Lovely Haberdashers','{\"item\": \"Bright Top Hat\", \"type\": \"payItemAndMoneys?\", \"amount\": 50, \"ifPaid\": {\"description\": \"\\\"Got it, bzzbzz,\\\" the bee says.\\n\\n\\\"Wonderfully! Beautiful!\\\" the bird squawks.\\n\\n\\\"Bzzbzz, thank you, dear,\\\" the bee says. \\\"And thank you, too,\\\" it flies over to you and delivers the modified hat. \\\"I hope you like it, as well. Bzzbzz.\\\"\", \"receiveItems\": \"Through My Heart\"}, \"ifNotPaid\": {\"description\": \"\\\"Gah!\\\" the bird squawks.\\n\\n\\\"Another time, perhaps. Bzzbzz,\\\" the bee says. \\\"Have a lovely rest of your day.\\\"\"}, \"description\": \"You\'re both greeted by a pair of dapper-looking characters... who happens to be a large bee, and a small bird.\\n\\n\\\"Bzzbzz; good day, good day,\\\" the bee says. \\\"Here for one of our hats?\\\"\\n\\n\\\"Of course they are!\\\" the bird squawks, wrapping some thread around the bee\'s stinger. \\\"50~~m~~, and we don\'t provide the Bright Top Hat!\\\"\"}',0,'lovely-haberdasher',NULL),(67,8,'Glowing Protojelly','{\"description\": \"You and %pet.name% spot a odd blob of jelly on the cave wall. It has a worrying glow to it, but %pet.name% just walks up and takes a bit before moving on.\", \"receiveItems\": [\"Glowing Protojelly\"]}',0,'glowing-protojelly',NULL),(68,9,'Tangled Up in Green','{\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"description\": \"As you\'re walking along the river-bank, %pet.name% spots a Sand Dollar tangled up in some Seaweed. They clean it up, and keep both.\", \"receiveItems\": [\"Sand Dollar\", \"Seaweed\"]}',0,'sand-dollar',NULL),(69,11,'Sand Worm!','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"dexterity\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 2}, \"buttonText\": \"*shakes fist at Sand Worm*\", \"description\": \"%pet.name% attempted to fight the creature off, but could not. You both fled, covered in Silica Grounds...\", \"receiveItems\": [\"Silica Grounds\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 3}, \"esteem\": 5, \"buttonText\": \"Whew!\", \"description\": \"In an impressive display of speed and strength, %pet.name% defeated the creature, and claimed its spice! ... s. Spices.\", \"receiveItems\": [\"Spice Rack\", \"Spice Rack\"]}, \"buttonText\": \"Egad!\", \"description\": \"As you and %pet.name% were walking through the desert, the sand began to shake, and a terrible sand worm burst forth!\", \"requiredRoll\": 20}',0,'sand-worm',NULL),(70,2,'Traveling Alchemist','{\"type\": \"payMoneys?\", \"amount\": 30, \"ifPaid\": {\"description\": \"\\\"Stay safe,\\\" he mumbles as you leave.\", \"receiveItems\": \"Werebane\"}, \"description\": \"You pass a traveling alchemist selling a liquid that can apparently cure lycanthropy. A bottle costs 30~~m~~...\"}',1,'alchemist',NULL),(72,6,'An Apiary','{\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"buttonText\": \"Buzz, buzz.\", \"description\": \"You pass an unkempt apiary, buzzing with bees. While %pet.name% braves the bees for some honey, you idly pick a Red Clover.\", \"receiveItems\": [\"Honeycomb\", \"Honeycomb\", \"Red Clover\"]}',0,'apiary',NULL),(73,8,'Gypsum Deposit','{\"exp\": {\"stats\": [\"nature\", \"crafts\"], \"amount\": 2}, \"description\": \"%pet.name% stops to mine some gypsum.\", \"receiveItems\": [\"Gypsum\", \"Gypsum\"]}',0,'gypsum-deposit',NULL),(74,10,'Very Cool Beans','{\"type\": \"petChallenge\", \"stats\": [\"strength\", \"stamina\", \"nature\"], \"ifFail\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 1}, \"buttonText\": \"Eh. Free Everice, at least.\", \"description\": \"You both hit and claw at the ice for a while, but %pet.name% is only able to break off a random chunk of ice.\", \"receiveItems\": [\"Everice\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"nature\"], \"amount\": 2}, \"esteem\": 4, \"buttonText\": \"Success!\", \"description\": \"It takes a lot of work, but %pet.name% finally breaks off a chunk of ice with the bag inside!\", \"receiveItems\": [\"Bag of Beans\", \"Everice\"]}, \"buttonText\": \"Let\'s go get it!\", \"description\": \"You spot a bag frozen in a sheet of ice that\'s covering an underground lake...\", \"requiredRoll\": 15}',0,'very-cool-beans',NULL),(75,6,'Statue Garden','{\"item\": \"Silver Key\", \"type\": \"payItem?\", \"ifPaid\": {\"type\": \"chooseOne\", \"buttons\": [\"Left, maybe?\", \"Right, perhaps?\"], \"outcomes\": [{\"esteem\": 4, \"buttonText\": \"Booze + swords = fun?\", \"description\": \"You find your way into the basement of the manor, the entrance to the secret passage snapping shut behind you. After exploring for a while, you find some wine, and %pet.name% calls you over to a sword _they_ found, which for some reason is wrapped in cloth? You both shrug, take the sword, and find your way out of the manor.\", \"receiveItems\": [\"Wrapped Sword\", \"Blueberry Wine\", \"Blueberry Wine\"]}, {\"id\": 30, \"type\": \"moveTo\", \"buttonText\": \"Twisty tunnels...\", \"description\": \"You follow the path, which leads to an underground river! The secret passage snaps shut behind you, leaving you to find another way out. You travel for a while, %pet.name% picking up a few rocks as you go, and finally emerge far from the village!\", \"receiveItems\": [\"Rock\", \"Rock\", \"Sand-covered... Something\"]}], \"description\": \"The statue moves to reveal an underground passage! You descend, and come to a fork...\"}, \"description\": \"As you pass through a statue garden on the grounds of the manor, one of the statues catches your eye: it\'s not covered in overgrown plants, like the others, and upon closer inspection, you see that one of _its_ eyes is actually a keyhole! (Kinda\' gross, but... also kinda\' cool!)\"}',0,'statue-garden',NULL),(76,9,'Triple Chest','{\"buttonText\": \"So chest!\", \"description\": \"You stop to do some fishing, and pull up something crazy-heavy - a Triple Chest!\", \"receiveItems\": [\"Triple Chest\"]}',0,'triple-chest',NULL),(77,3,'Flying Keys, Only','{\"item\": \"Winged Key\", \"type\": \"payItem?\", \"ifPaid\": {\"type\": \"petChallenge\", \"stats\": [\"dexterity\", \"stamina\", \"brawl\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 2}, \"type\": \"onward\", \"esteem\": -2, \"safety\": -2, \"buttonText\": \"Onward...\", \"description\": \"After many jumps and tumbles, the wings fly off into the sunset, never to be seen again... (Dang!)\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"type\": \"onward\", \"esteem\": 4, \"buttonText\": \"Onward!\", \"description\": \"The whelp and your pet catch the wings, which it lets you keep!\", \"receiveItems\": [\"Wings\"]}, \"buttonText\": \"Catch the wings!\", \"description\": \"The whelp takes the key and chews the wings off, causing them to fly around!\", \"requiredRoll\": \"10\"}, \"description\": \"A dragon whelp stands in your path, laying on a pile of gold keys. It looks expectantly towards a small note in the pile that reads \\\"Flying Keys Only\\\".\"}',1,'community/flying-keys-only','🐍'),(78,6,'A Fae Court Feast','{\"type\": \"chooseOne\", \"buttons\": [\"Spy Matters\", \"A Feast For All\"], \"outcomes\": [{\"exp\": {\"stats\": [\"stealth\"], \"amount\": 2}, \"type\": \"onward\", \"buttonText\": \"Fae Court Spy\", \"description\": \"%pet.name% slinks through the crowd, gathering intel.\"}, {\"food\": 12, \"type\": \"onward\", \"buttonText\": \"Fae Court Feast\", \"description\": \"%pet.name% checks out the banquet table, picking over the various foods, and finds a few delicacies.\"}], \"description\": \"A room in the Manor opens on a Fae Court feast - will %pet.name% be a spy, or a gourmand?\"}',0,'community/fae-court-feast','%user:2452.name%'),(79,5,'Phishing Lessons','{\"item\": \"Password\", \"type\": \"payItem?\", \"ifPaid\": {\"type\": \"petChallenge\", \"stats\": [\"perception\", \"intelligence\", \"science\"], \"ifFail\": {\"type\": \"onward\", \"esteem\": -10, \"safety\": -5, \"buttonText\": \"<_<\", \"description\": \"Not knowing that much about Internet safety, %pet.name% manages to download even more malware to the laptop. One of them was a ransomware program: it swiftly locked the files behind a paywall, and insisted on needing 50 Cryptocurrency Wallets.\\n\\nThe Painter Gecko sighs in disbelief: \\\"This is probably the tenth laptop I\'ve had ruined...\\\"\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"science\"], \"amount\": 4}, \"love\": 10, \"type\": \"onward\", \"esteem\": 15, \"buttonText\": \"Better do that\", \"description\": \"%pet.name% is wise enough to search for the initial file the `.exe` file planted itself into. Upon removing it, the rampant advertisements disappear in a snap. The Painter Gecko seems relieved, finally getting their thanks to you and %pet.name%. They insist that they\'ll run their laptop with an antivirus or sort afterwards.\"}, \"buttonText\": \"*fingers crossed*\", \"description\": \"The laptop\'s screen is met with a pop-up that states: \\\"Congratulations, you won! Click here to redeem your free Digital Camera!\\\" And then another, and a third, and a fourth. The Painter Gecko gets nervous: \\\"No... No!!\\\"\\n\\nIn major panic, they ask for the help of %pet.name%.\", \"requiredRoll\": \"20\"}, \"ifNotPaid\": {\"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"You give the gecko a stern look and move on.\"}, \"description\": \"You see a lone Painter Gecko sitting on a rock, tapping away on their laptop. While they seem shady, %pet.name% approaches them in interest. Upon having a chat with each other, the Painter Gecko reveals that they\'re going to pirate a new, sought-out video game. They had found a `.zip` file containing the assets, or so they say.\\n\\nTo open the suspicious `.zip` file, they need a Password.\"}',0,'community/phishing-lessons','%user:2660.name%'),(80,2,'Heavy Stuff','{\"type\": \"petChallenge\", \"stats\": [\"strength\"], \"ifFail\": {\"type\": \"onward\", \"buttonText\": \"I didn\'t need flour anyways.\", \"description\": \"%pet.name% failed to pick the flour up. They dropped it and it went everywhere. %pet.name% picked up some Silica Grounds and pretended that they had always wanted to pick that up.\", \"receiveItems\": [\"Silica Grounds\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"type\": \"onward\", \"buttonText\": \"Move on.\", \"description\": \"%pet.name% picked the bag of flour up. It\'s some Wheat Flour.\", \"receiveItems\": [\"Wheat Flour\"]}, \"buttonText\": \"Pick it up!\", \"description\": \"A small bag of flour was found on the floor.\", \"requiredRoll\": \"10\"}',0,'community/heavy-stuff','an anonymous player'),(81,4,'Yayyy! Bread!','{\"type\": \"payMoneys?\", \"amount\": 5, \"ifPaid\": {\"type\": \"onward\", \"buttonText\": \"Yayy bread for me!\", \"description\": \"\\\"YAYYY! BREAD FOR YOU!!\\\" The magpie said while handing you the bread, \\\"Come again soon! More bread for you!\\\"\", \"receiveItems\": [\"Slice of Bread\"]}, \"description\": \"A small magpie was standing on a basket. \\\"Bread! Bread for 5 moneys!\\\" It squawked, flapping its wings excitedly, \\\"You there! Do you want bread?!\\\"\"}',0,'community/yayyy-bread','an anonymous player'),(82,3,'Salad of Wisdom','{\"type\": \"chooseOne\", \"buttons\": [\"Approach!\", \"Leave\"], \"outcomes\": [{\"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"The Salad opens his eyes, his tongue lolling out in a smile. He begins to speak.\\n\\n\\\"Ha wa wa, haaa. Ha wa wa wa. Ha ba ba ba, ha wa wa wa, haaa.\\\"\\n\\n%pet.name% doesn\'t really understand what they said, but they feel inspired.\\n\\nThe Salad gives %pet.name% a knowing nod, rolls them a tenni-- er, Green Sportsball Ball, and sends them on their way.\", \"receiveItems\": [\"Green Sportsball Ball\"], \"statusEffect\": {\"status\": \"Inspired\", \"duration\": 480, \"maxDuration\": 480}}, {\"type\": \"onward\", \"buttonText\": \"Leave\", \"description\": \"Best not to disturb the Salad\'s meditation. You continue onward, but %pet.name% can\'t help but feel inspired by the Salad\'s aura of wisdom.\", \"statusEffect\": {\"status\": \"Inspired\", \"duration\": 480, \"maxDuration\": 480}}], \"description\": \"You come across a yellow Salad meditating on a fluffy white blanket. Their aura emanates great wisdom but they have not noticed you yet. Next to them, is a sign beckoning you to approach for a free wisdom.\"}',0,'community/salad-of-wisdom','%user:2653.name% (who gets way too much dopamine from the \"dog of wisdom\" meme)'),(83,8,'Like Moths...','{\"type\": \"petChallenge\", \"stats\": [\"brawl\", \"dexterity\"], \"ifFail\": {\"type\": \"onward\", \"buttonText\": \"You\'ll get them next time!\", \"description\": \"%pet.name% swipes to grab the moths, and misses. They flutter away.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"%pet.name% successfully captures a few moths.\", \"receiveItems\": [\"Moth\", \"Moth \", \"Moth\"]}, \"buttonText\": \"That\'s no moon!\", \"description\": \"A flurry of moths swarm around an old mining lamp, mistaking its warm glow for the moon. You might be able to catch some.\", \"requiredRoll\": \"15\"}',0,'community/like-moths','%user:2653.name%'),(84,4,'Worm \"Merchant\"','{\"type\": \"chooseOne\", \"buttons\": [\"Fine, I\'ll take some worms.\", \"Nah. No way I\'m buying.\"], \"outcomes\": [{\"type\": \"payMoneys?\", \"amount\": 2, \"ifPaid\": {\"type\": \"onward\", \"buttonText\": \"Yay, worms for me...?\", \"description\": \"\\\"Thank you for purchasing my worms! I\'ll unblock the path now,\\\" it squawked, then flew away.\", \"receiveItems\": [\"Worms\"]}, \"description\": \"\\\"2 moneys for the worms,\\\" the magpie squawked happily. \\\"Just 2 moneys!\\\"\"}, {\"type\": \"petChallenge\", \"stats\": [\"brawl\", \"dexterity\"], \"ifFail\": {\"type\": \"onward\", \"buttonText\": \"That was embarrassing.\", \"description\": \"The magpie beat you up. It then flew away, leaving nothing behind. You heard it grumbling as it flew past you, nearly smacking you on the face.\\n\\nOh well.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"type\": \"onward\", \"buttonText\": \"Oh well, I\'ll take it.\", \"description\": \"Turns out magpies are incredibly easy to beat up. Or maybe this one is just weak. It flew away with its basket, leaving behind two feathers as a \\\"prize for winning.\\\" Huh. You also gain some exp, because that\'s how battling works, apparently.\", \"receiveItems\": [\"Feathers\", \"Feathers\"]}, \"buttonText\": \"Oh yeah! Let\'s beat that bird up!!\", \"description\": \"\\\"Then I\'m not moving!\\\" It squawks.\\n\\nWait: can\'t you just beat it up to make it go away?\", \"requiredRoll\": \"10\"}], \"description\": \"A magpie holding a basket filled with wriggly worms is standing on the path, blocking the way. \\\"Worms for moneys,\\\" it squawks. \\\"Buy my worms or I don\'t unblock the path!\\\"\"}',1,'community/worm-merchant','%user:1943.name%'),(85,5,'A Fair Game','{\"type\": \"payMoneys?\", \"amount\": 20, \"ifPaid\": {\"type\": \"petChallenge\", \"stats\": [\"perception\", \"dexterity\", \"strength\"], \"ifFail\": {\"love\": 4, \"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"\\\"Ah. No luck. Maybe next time?\\\" %pet.name% declines another go. These things are rigged anyway. Still, %pet.name% had a lot of fun today. \", \"receiveItems\": [\"Popcorn\", \"Blue Fairy Floss\", \"Red Juice\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"love\": 4, \"type\": \"onward\", \"esteem\": 4, \"buttonText\": \"That was fun!\", \"description\": \"%pet.name% can\'t believe their luck. They did it! %pet.name% gleefully receives their prize from the bemused operator: a Fluff Heart, which they can redeem for a plushy at the trader! Aww!!\", \"receiveItems\": [\"Fluff Heart\", \"Pink Fairy Floss\", \"Buttered Popcorn\", \"Tall Glass of Yellownade\"]}, \"buttonText\": \"Sweet! Hold my drink!\", \"description\": \"%pet.name% steps up to the challenge...\", \"requiredRoll\": \"20\"}, \"description\": \"\\\"What\'s this—a fun fair?!\\\" As %pet.name% makes their way through the fairground, a game of coconut shy catches their eye. The operator smiles, \\\"20~~m~~ to play a round!\\\"\"}',0,'community/a-fair-game','%user:3148.name%'),(86,2,'Naner-eater','{\"item\": \"Naner\", \"type\": \"payItem?\", \"ifPaid\": {\"type\": \"onward\", \"buttonText\": \"*nod*\", \"description\": \"You give the friendly snail a Naner, and it thanks you for your generosity by gifting you some Quintessence!\", \"receiveItems\": [\"Quintessence\"]}, \"ifNotPaid\": {\"type\": \"onward\", \"buttonText\": \"*nod*\", \"description\": \"The friendly snail understands, and thanks you anyway.\"}, \"description\": \"You meet a friendly snail who offers you some Quintessence in return for a tasty Naner.\"}',0,'community/naner-eater','%user:2908.name%'),(87,14,'Green & Lumpy','{\"type\": \"chooseOne\", \"buttons\": [\"Uhhh yeah, avocado!\", \"Suuuuure, I could use an avocado....\", \"There\'s something not quite right about this character here\"], \"outcomes\": [{\"item\": \"Avocado\", \"type\": \"payItem?\", \"ifPaid\": {\"type\": \"onward\", \"buttonText\": \"Alright then...\", \"description\": \"\\\"Avocado!\\\"\\nThe person(?) gives you a different, lint-covered avocado from their bag.\", \"receiveItems\": [\"Fluff\", \"Avocado\"]}, \"description\": \"Give the person(?) an avocado?\"}, {\"type\": \"payMoneys?\", \"amount\": 3, \"ifPaid\": {\"type\": \"onward\", \"buttonText\": \"\\\"Avocado!\\\"\", \"description\": \"The person(?) hands you a lint-covered avocado from their bag\\n\\\"Avocado!\\\"\", \"receiveItems\": [\"Fluff\", \"Avocado\"]}, \"description\": \"Give the person(?) 3 moneys, hoping to get an avocado in return?\"}, {\"type\": \"petChallenge\", \"stats\": [\"stealth\"], \"ifFail\": {\"exp\": {\"stats\": [\"stealth\"], \"amount\": 5}, \"type\": \"onward\", \"esteem\": -2, \"buttonText\": \"AHHH BROWN AVOCADO\", \"description\": \"The avocado-person notices your pet\'s lame attempt to be sneaky.\\n\\\"AVOCADO! AVOCADO! AVOCADO!\\\" it cries in a harsh, annoying tone. \\nAs you start backing away, the avocado-person throws avocados at you. Unfortunately, they\'re all very over-ripe and unusable... :(\"}, \"baseRoll\": 20, \"ifSuccess\": {\"type\": \"onward\", \"esteem\": 2, \"buttonText\": \"Avocados!\", \"description\": \"Your pet very carefully notices a tear in the avocado-person\'s jumpsuit and deftly removes five perfectly-ripe avocados\", \"receiveItems\": [\"Avocado\", \"Avocado\", \"Avocado\", \"Avocado\", \"Avocado\"]}, \"buttonText\": \"I bet there\'s so many avocados inside it!\", \"description\": \"You notice that the person(?) seems to be made of a bunch of avocados dumped into a light green jumpsuit...\", \"requiredRoll\": \"20\"}], \"description\": \"A curiously lumpy person(?) in a light green jumpsuit carrying a lumpy sack appears in front of you. With a grating voice he says,\\n\\\"Avocado?\\\"\"}',0,'community/avocado','%user:2942.name%'),(88,5,'A Captivating Arena','{\"type\": \"chooseOne\", \"buttons\": [\"Watch a game.\", \"Try fighting in the arena.\"], \"outcomes\": [{\"food\": 2, \"type\": \"onward\", \"safety\": 2, \"buttonText\": \"Onward!\", \"description\": \"The fighting was entertaining. %pet.name% felt inspired as you left the arena.\", \"statusEffect\": {\"status\": \"Inspired\", \"duration\": 480, \"maxDuration\": 480}}, {\"type\": \"petChallenge\", \"stats\": [\"strength\", \"brawl\", \"stamina\", \"dexterity\", \"stealth\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"food\": 4, \"love\": 2, \"type\": \"onward\", \"esteem\": -4, \"buttonText\": \"Onward!\", \"description\": \"%pet.name% lost the round, and left the arena defeated. The audience cheered regardless, thanking you for entertaining them.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 4}, \"food\": 4, \"love\": 4, \"type\": \"onward\", \"esteem\": 4, \"buttonText\": \"Onward!\", \"description\": \"%pet.name% won the round, and the audience cheered!\"}, \"buttonText\": \"Let\'s fight!\", \"description\": \"%pet.name% was welcomed into the arena and matched with an opponent of similar size. They looked to be an experienced fighter. They stared at %pet.name% and growled.\", \"requiredRoll\": \"20\"}], \"description\": \"You saw an arena in the middle of the town. Two fighters are fighting in the arena, and the crowd around is cheering loudly.\"}',1,'community/captivating-arena','%user:2029.name%'),(89,8,'Dealings in the Dark','{\"type\": \"chooseOne\", \"buttons\": [\"Jump out and challenge!\", \"Sneak in and steal!\"], \"outcomes\": [{\"type\": \"petChallenge\", \"stats\": [\"brawl\", \"stamina\", \"strength\"], \"ifFail\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 1}, \"food\": 4, \"type\": \"onward\", \"esteem\": -2, \"safety\": -2, \"buttonText\": \"Onward!\", \"description\": \"The vampires fought back viciously! You were forced to flee! Fortunately, they did not chase you for far, and you were able to go back to your original path.\"}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"brawl\"], \"amount\": 4}, \"food\": 4, \"type\": \"onward\", \"esteem\": 4, \"buttonText\": \"Onward!\", \"description\": \"%pet.name% defeated the vampires, and as they were fleeing the scene, %pet.name% snatched a bunch of things from them!\", \"receiveItems\": [\"Talon\", \"Linens and Things\", \"Blood Wine\", \"Gold Bar\"]}, \"buttonText\": \"Try it!\", \"description\": \"%pet.name% jumped out and took on the vampires!!\", \"requiredRoll\": \"20\"}, {\"type\": \"petChallenge\", \"stats\": [\"perception\"], \"ifFail\": {\"exp\": {\"stats\": [\"stealth\"], \"amount\": 1}, \"type\": \"onward\", \"esteem\": -2, \"safety\": -2, \"buttonText\": \"Onward!\", \"description\": \"%pet.name% was caught red-handed! The vampires chased you out, but before going, you both managed to grab something from them.\", \"receiveItems\": [\"Linens and Things\"]}, \"baseRoll\": 20, \"ifSuccess\": {\"exp\": {\"stats\": [\"stealth\"], \"amount\": 3}, \"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"The vampire did not notice %pet.name% at all! Turns out they were trading beddings for their coffins for gold; %pet.name% was able to take a couple of things, before retreating with their prizes!\", \"receiveItems\": [\"Linens and Things\", \"Linens and Things\", \"Gold Bar\", \"Gold Bar\"]}, \"buttonText\": \"Sneak in! (And steal!)\", \"description\": \"The vampires were all distracted and immersed in eager discussions of prices...\", \"requiredRoll\": \"15\"}], \"description\": \"You heard mumbling voices in the caves. You carefully approached and saw a vampire gathering! It seems that the vampires are trading with each other. What should %pet.name% do?\"}',0,'community/dealings-in-the-dark','%user:2029.name%'),(90,5,'Pluot Parade','{\"food\": 8, \"love\": 4, \"type\": \"onward\", \"buttonText\": \"Onward!\", \"description\": \"You stop in town to watch a parade that appears to be fruit based? Asking some locals, you learn it\'s a \\\"Pluot Parade\\\". You both eat some pluot donuts, have some pluot juice, and grab a couple pluots to take home. Neither of you have the faintest clue what a \\\"pluot\\\" is, but it seems pretty similar to an Apricot, so, 🤷‍♀️, let\'s just say you brought two Apricots home.\", \"receiveItems\": [\"Apricot\", \"Apricot\"]}',0,'pluot-parade',NULL);
