-- Dumping data for table `item`
--

LOCK TABLES `item` WRITE;
/*!40000 ALTER TABLE `item` DISABLE KEYS */;
INSERT INTO `item` VALUES (1,'Orange','Have you ever peeled open an orange, started to tear the slices apart - maybe a bit of juice squirts out - and think \"dang: here this thing was, just tryin\' to make more trees. Although I guess it\'s been bred to have no seeds. And be maximally sweet and easy to peel. Being a living creature is _weird_. Is it weirder for oranges, or for me, I wonder?\" \\*chomp\\* \"Mm. Delicious.\"','fruit/orange',NULL,NULL,2,6,2,35,0,0,NULL,NULL,NULL,0,NULL,0,1),(2,'Red',NULL,'fruit/red',NULL,NULL,3,6,3,34,0,0,NULL,NULL,NULL,0,NULL,0,1),(3,'Blueberries','There\'s a story about a god of love who wears a crown of blueberries...\r\n\r\nI forget how it goes, though.','fruit/blueberries',NULL,NULL,4,4,5,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(4,'Naner','A common fruit to find a tropical island, really. Nothing to get too fussed about one way or another.','fruit/naner',NULL,NULL,5,6,7,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(5,'Blackberries','Sorry, I realize these berries are actually more purple or blue than black, and that this could cause a lot of confusion! I hope you don\'t quit the game over it; _most_ of the items have much more reasonable & descriptive names, like \"Coffee Bean Tea\".','fruit/blackberries',NULL,NULL,6,4,4,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(6,'Carrot','Unfortunately, Carrots cannot be planted on the island on their own. They need the protection of a bigger, stronger root vegetable.','veggie/carrot',NULL,NULL,7,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(7,'Onion','\"What can you do with onions?\" \"WHAT CAN YOU DO WITH ONIONS?!?\" I mean, Onion Rings, for one! Coat \'em in a mixture of flour and Baking Soda... dip \'em in Oil... MM!\n\n<small>\"What can you do with onions.\" \\*shakes head\\* Some people; honestly...</small>','veggie/onion',NULL,NULL,8,4,14,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(8,'Celery','In the right hands, Celery is a simple, low-calorie snack.\n\nIn the _wrong_ hands? \\*shudders\\*','veggie/celery',NULL,NULL,9,4,34,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(9,'Grandparoot','For a long time, it was thought that Grandparoot extract - today commonly referred to as Aging Powder - was a critical ingredient in making the Philosopher\'s Stone, but very few alchemists still hold this belief.\r\n\r\nYou can create your _own_ Aging Powder by caaaaaaarefully preparing Grandparoot all by itself!','veggie/grandparoot',NULL,NULL,NULL,0,42,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(10,'Aging Powder','Aging & fermenting can take a long time. Thankfully, this powder - which apparently has the ability to warp the very fabric of space-time - can speed up this process.\r\n\r\nYou\'d think there\'d be a better use for the stuff than growing mushrooms on Crooked Sticks.','ingredient/aging-powder',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(11,'Sweet Beet','A root vegetable that\'s perplexingly unrelated to the Phat Beat.\r\n\r\nNature\'s weird like that, sometimes.','veggie/sweet-beet',NULL,NULL,10,6,8,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(12,'Sugar','\"The brain is a machine for turning glucose into mistakes.\" ~ @Neuro_Skeptic','ingredient/sugar',NULL,NULL,11,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(13,'Creamy Milk','I\'ve heard it said that humans are the only animal that drink milk past infancy. We\'re also the only animal to invent cars, computers, vaccines, and the International Space Station.\r\n\r\nHumans are pretty amazing creatures.','animal/milk',NULL,NULL,12,4,10,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(14,'Egg','What kind of bird might this egg have grown up to be? Who knows! It\'s like nature\'s original loot box, and you\'re just gonna\' _turn it into a flan_, or some odd business!','animal/egg',NULL,NULL,13,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(15,'Wheat','Grind it into flour, or water it, and grow some flower... s. Wheat\'s good for all your homonymic needs!','veggie/wheat',NULL,NULL,14,4,1,NULL,60,0,NULL,NULL,NULL,0,NULL,0,1),(16,'Wheat Flour',NULL,'ingredient/wheat-flour',NULL,NULL,NULL,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(17,'Rice','I was told that wheat contains about 65% water, while rice consists of 68% water. That\'s why, when I\'m boiling wheat, I always put in just a liiiiittle less water than when I\'m boiling rice. I asked an AI chat bot for help figuring out the exact numbers, but it seemed _really_ confused by what I was talking about, so, I dunno, I\'m thinking this whole AI thing might just be a fad.','veggie/rice',NULL,NULL,15,4,6,NULL,60,0,NULL,NULL,NULL,0,NULL,0,1),(18,'Rice Flour',NULL,'ingredient/rice-flour',NULL,NULL,NULL,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(19,'Wheat Flower',NULL,'flower/wheat',NULL,NULL,16,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(20,'Rice Flower',NULL,'flower/rice',NULL,NULL,79,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(21,'Tea Leaves','This leaf is a bit bitter to just eat, but maybe if you, like, flavored some hot water with it, that\'d be good? Couldn\'t hurt to try!\r\n\r\n<small>Psst, hey!</small>\r\n\r\n<small>Over here!</small>\r\n\r\n<small>So, I hate to break the fourth wall - wait, who am I kidding? I love breaking the fourth wall! - but anyway: this game assumes you have infinite water! And salt! So you can cook without worrying about those. Handy, right?</small>\r\n\r\n<small>Okay, I\'m done now. I\'ll let you get back to playing.</small>','veggie/tea-leaves',NULL,NULL,NULL,2,NULL,289,15,0,NULL,NULL,NULL,0,NULL,0,1),(22,'Coffee Beans',NULL,'veggie/coffee',NULL,NULL,NULL,4,NULL,NULL,15,0,NULL,NULL,NULL,0,NULL,0,1),(23,'Cocoa Beans','Wait, are Cocoa Beans technically, like, seeds, or nuts, or something? And come to think of it, are seeds and nuts vegetables? HAS CHOCOLATE SECRETLY BEEN VEGETABLES THIS WHOLE TIME?!??','veggie/cocoa',NULL,NULL,NULL,4,NULL,NULL,15,0,NULL,NULL,NULL,0,NULL,0,1),(24,'Corn','Corn, corn,\r\nthe most-toothsome vegetable,\r\nthe more heat and oil,\r\nthe more it\'s delectable.','veggie/corn',NULL,NULL,18,5,13,NULL,60,0,NULL,NULL,NULL,0,NULL,0,1),(25,'Corn Syrup','Was this extracted from the dreams of cornstalks, or the nightmares of nutritionists? Either way is fine — it only has a subtle effect on the flavor.','ingredient/corn-syrup',NULL,NULL,NULL,3,NULL,211,0,0,NULL,NULL,NULL,0,NULL,0,1),(26,'Orange Gummies','When people ask what my favorite color is, I say \"transparent orange\". Not a color I often wear, though...','candy/gummy/orange',NULL,NULL,19,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(27,'Red Gummies','Red Gummies are red;<br>\r\nBlue Gummies are blue;<br>\r\nAll gummies are best<br>\r\nwhen eaten with you.','candy/gummy/red',NULL,NULL,20,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(28,'Blue Gummies',NULL,'candy/gummy/blue',NULL,NULL,21,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(29,'Purple Gummies',NULL,'candy/gummy/purple',NULL,NULL,22,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(30,'Mirepoix','Invented by the Duke of Mirepoix, who has been described as \"an incompetent and mediocre individual... who owed his vast fortune to the affection Louis XV felt toward his wife,\" which I\'m pretty sure is fancy-person-talk for \"King Louis XV and Lady Mirepoix were bangin\' on the reg\". I can only hope it was an open, honest, & fully-consensual arrangement among the three of them. Whatever the case, the Duke of Mirepoix created a staple of French cuisine that survives to this day. So that\'s pretty neat.','ingredient/mirepoix',NULL,NULL,23,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(31,'Naner Puddin\'','Made with real Naners!','dessert/naner-puddin',NULL,NULL,24,14,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(32,'Pamplemousse','It kind of looks like a giant Orange, but NOTHING COULD BE FURTHER FROM THE TRUTH.\r\n\r\nWell, unless you have some Megalium. Then I guess it\'s actually super-close to the truth...','fruit/pamplemousse',NULL,NULL,25,8,19,36,0,0,NULL,NULL,NULL,0,NULL,0,1),(33,'Fish','In French, \"Fish\" is \"Poisson\", but in French, \"Poison\" is \"Poison\", so... be careful with your \"s\"es when ordering Fish in France!','animal/meat/fish',NULL,NULL,26,10,31,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(34,'Fluff','You might assume that this innocuous-looking bit of Fluff came from the back of an animal, but really, it could have come from in or around the ear, nose, or any number of mammalian orifices! There\'s really no way to tell!','ambiguous/fluff',NULL,NULL,NULL,0,NULL,120,30,0,NULL,NULL,NULL,0,NULL,0,1),(35,'Scales','The fish kind. Not the musical kind. Or the weight kind. Don\'t feel too bad: there\'s a lot of different kinds of scales - it\'s easy to get mixed up.','animal/scales',NULL,NULL,NULL,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(36,'Music Note','A single note can be the beginning of a love story, or the finale of a tragic opera. What will it be for you?','music/note',NULL,NULL,NULL,8,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(37,'Musical Scales','La La <sup>la la la</sup> la <sub>laaaa...</sub>','animal/scales-musical',NULL,NULL,NULL,64,NULL,NULL,0,0,5,NULL,NULL,0,NULL,0,7),(38,'Toad Legs','I don\'t know whether or not _you\'ll_ eat Toad Legs, but I can guarantee your pets will.','animal/meat/legs-frog',NULL,NULL,27,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(39,'Toadstool','If a toad can have one these on its back, I can have one on my head. That\'s just science.','fungus/toadstool',NULL,NULL,28,2,39,5,0,0,NULL,NULL,NULL,0,NULL,0,1),(40,'Plastic','A bit of raw plastic, waiting to be molded into something greater.','resource/plastic',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(41,'Mermaid Egg','Don\'t worry: I\'m _almost totally positive_ it hasn\'t been fertilized.\n\nAlmost.','animal/egg-mermaid',NULL,NULL,29,6,NULL,255,0,0,NULL,NULL,NULL,0,NULL,0,1),(42,'Crooked Stick','Crooked Stick, Crooked Stick, carved with a note;<br>\r\nCrooked Stick, Crooked Stick, make me a boat.<br>\r\nCrooked Boat, Crooked Boat, let\'s float away,<br>\r\nand like the note says, boat, we\'ll return one day.','plant/stick-crooked',NULL,1,NULL,4,9,NULL,240,0,NULL,NULL,NULL,0,NULL,0,1),(43,'Ginger','Ah, my favorite herbaceous perennial which grows annual pseudostems.\r\n\r\nWhat\'s my favorite herbaceous perennial which _doesn\'t_ grow annual pseudostems?\r\n\r\n_I\'ll_ never tell ;)','veggie/ginger',NULL,NULL,30,2,37,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(44,'Ginger Tea',NULL,'tea/ginger',NULL,NULL,31,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(45,'Sweet Ginger Tea',NULL,'tea/ginger',NULL,NULL,32,6,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(46,'Black Tea',NULL,'tea/black',NULL,NULL,33,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(47,'Sweet Black Tea',NULL,'tea/black',NULL,NULL,34,3,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(48,'Baking Soda','Baking Soda isn\'t useful only in baking! Cooked with green vegetables, it can make them even _greener!_ It can also be used to tenderize meats, reduce fungal growth, and even to put out some kinds of fires!\r\n\r\nIt\'s versatile stuff!','mineral/nahcolite',NULL,NULL,NULL,1,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(49,'Limestone','If you don\'t have enough Limestone to make a Great Sphinx, you could at least turn a block into some Baking Soda. That\'s _almost_ as cool... >_>','mineral/limestone',NULL,NULL,NULL,10,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(50,'Book of Flowers','A book that explains the meaning behind many flowers. Read before sending flowers to someone else! (You wouldn\'t want to send the wrong message! THAT COULD BE DISASTROUS!)','book/flowers','[[\"Read\", \"bookOfFlowers/#/read\"]]',5,NULL,0,NULL,NULL,120,0,NULL,NULL,NULL,0,NULL,0,1),(51,'Agrimony','It has a pleasant, slightly sweet and pungent aroma, with hints of lemon and mint.','flower/agrimony',NULL,NULL,35,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(52,'Bird\'s-foot Trefoil','The Bird\'s-foot Trefoil is fine, but - personally - I prefer the Fish\'s-gill Quatrefoil.','flower/birds-foot-trefoil',NULL,NULL,36,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(53,'Purple Violet','A poor substitute for the Purple Ultra-violet. To be fair, the Purple Ultra-violet is a critically-endangered species, so it\'d probably be, like, immoral, or something, to just _have_ one for funsies...','flower/violet-purple',NULL,NULL,37,2,NULL,9,0,0,NULL,NULL,NULL,0,NULL,0,1),(54,'Red Clover',NULL,'flower/clover-red',NULL,431,38,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(55,'Witch-hazel','A flower said to possess magical properties<sup><small>_[citation needed]_</small></sup>.','flower/witch-hazel',NULL,NULL,39,2,35,NULL,0,0,7,NULL,NULL,0,NULL,0,1),(56,'Viscaria','You can\'t just live viscarialy through others!\r\n\r\nThat\'s what my mom used to tell me.\r\n\r\nIn that one recurring dream. With all the flower puns.\r\n\r\nOr is it \"wordplay\" in that case? I always forget.\r\n\r\nAlso - now that I\'m thinking about it - I don\'t think I\'ve actually had that dream in a while?\r\n\r\nHuh.\r\n\r\nBrains are weird.','flower/viscaria',NULL,NULL,40,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(57,'Iris','Gross!\r\n\r\nOh, wait, it\'s the flower one. Not the eye one.\r\n\r\nPretty!','flower/iris',NULL,NULL,41,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(58,'Coriander Flower',NULL,'flower/coriander',NULL,NULL,42,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(59,'Green Carnation','Oops: carnations are apparently CRAZY-hard to draw >_> Sorry about that :|','flower/carnation-green',NULL,222,43,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(60,'Narcissus','This flower means \"you love no one but yourself.\"\r\n\r\nHarsh!','flower/narcissus',NULL,NULL,44,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(61,'Chanterelle','<small>Chanterelle!</small><br>\r\nChanterelle!<br>\r\nCHANTERELLE!<br>\r\n<br>\r\nIt _is_ fun to chant. Unfortunately, the origin of the name is _way_ less fun; something to do with ancient Greek drinking vessels, or whatever.','fungus/chanterelle',NULL,NULL,45,4,40,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(62,'Cream of Tartar','Have you ever wondered what Cream of Tartar is? Like, it\'s dry, so why is it called a cream? And what\'s a Tartar? Wasn\'t that a creature in Star Wars, or something? (\"I thought they smelled bad... ... on the outside!\")\r\n\r\nWell I sure did! So I looked it up on Wikipedia and... wait... well, okay, so I still don\'t know why it\'s called a \"Cream\", but I DO now know that it\'s made from tartaric acid, AND it\'s a byproduct of making wine, because grapes are apparently full of tartaric acid! So... that\'s cool! I mean, we don\'t have grapes in this game, but, like, whatever, let\'s pretend that, um, Blackberries also have tartaric acid? Sure. Why not. That makes sense. I mean, this is the same game that calls a latte \"Sweet Coffee Bean Tea with Mammal Extract\", so, you know, whatever.','mineral/KC4H5O6',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(63,'Blackberry Wine','\"In wine there is wisdom ... in water there is bacteria.\" ~Benjamin Franklin','wine/blackberry',NULL,NULL,46,0,NULL,NULL,15,0,NULL,NULL,NULL,0,NULL,0,1),(64,'Blueberry Wine','The label warns: \"Contents may cause drinker to temporarily perceive the true nature of reality. Also pairs well with cheese.\"','wine/blueberry',NULL,NULL,47,0,NULL,NULL,15,0,NULL,NULL,NULL,0,NULL,0,1),(65,'Butter','I know someone who used to use \"Butter\" as a nickname for-- well, on second thought, I probably shouldn\'t say. Just in case you\'re playing Poppy Seed Pets at work, or something.','animal/butter',NULL,NULL,48,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(66,'Pancakes','It\'s cakes you can make in a pan! Wowzers!','bread/pancakes',NULL,NULL,49,16,NULL,139,0,0,NULL,NULL,NULL,0,NULL,0,1),(67,'Paper','New paper smells a little like Melowatern, right? I feel like it does, faintly.\r\n\r\nNo, I\'m serious, here, smell it! Smell it!! _I\'m not crazy; **smell the paper!!**_','resource/paper',NULL,NULL,460,4,NULL,NULL,60,0,NULL,NULL,NULL,0,NULL,0,1),(68,'String','Take hold of Fluff,<br>all tangled up.<br>Straighten out, but have no doubt: it\'s not enough.<br>Hand over hand -<br>individual strand -<br>taught and tight; your mind takes flight; String under your command.','resource/string',NULL,NULL,NULL,0,NULL,NULL,30,1,NULL,NULL,NULL,0,NULL,0,1),(69,'Crooked Fishing Rod','This fishing rod also has the ability \"When your pet gathers a Crooked Fish, it gets another Crooked Fish\", but as there aren\'t any Crooked Fish in the game, that ability is omitted, for brevity. You know, to spare you wasting your time reading useless nonsense that doesn\'t help you in any way, shape, or form! It\'s just good game design!','tool/fishing-rod/crooked',NULL,3,NULL,0,NULL,NULL,300,3,NULL,NULL,NULL,0,NULL,0,1),(70,'Baker\'s Box','This box contains a random assortment of items that a baker or other cook might find useful.\r\n\r\nOpen it to find out what\'s inside!','box/baker','[[\"Open\", \"box/bakers/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(71,'Fruits & Veggies Box','This box contains a random assortment of fruits and veggies.\r\n\r\nOpen it to find out what\'s inside!','box/fruits-n-veggies','[[\"Open\", \"box/fruits-n-veggies/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(72,'Orange Hard Candy',NULL,'candy/hard/orange',NULL,NULL,50,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(73,'Red Hard Candy',NULL,'candy/hard/red',NULL,NULL,51,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(74,'Blue Hard Candy',NULL,'candy/hard/blue',NULL,NULL,52,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(75,'Purple Hard Candy','Just add Corn Syrup, and you have yourself some Purple Gummies!\r\n\r\nEr, well, I mean, you can\'t do it _now_. You have to do it, like, up-front, you know? As you\'re cooking.','candy/hard/purple',NULL,NULL,53,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(76,'White Cloth',NULL,'cloth/white',NULL,NULL,NULL,0,NULL,NULL,45,1,NULL,NULL,NULL,0,NULL,0,1),(77,'Stereotypical Torch','Just like in the movies!','tool/torch/stereotypical',NULL,2,NULL,0,NULL,NULL,300,4,NULL,NULL,NULL,0,NULL,0,1),(78,'Wooden Sword','Many a living room knight has wielded this very weapon, fighting dragons and shadows alike.','tool/sword/wood',NULL,4,NULL,0,NULL,NULL,300,3,NULL,NULL,NULL,0,NULL,0,1),(79,'4th of July Box',NULL,'box/july-4th','[[\"Open\", \"box/july4/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(80,'Hot Dog','Your perception of reality, and the truth of reality, are not always related. For example, the Hot Dog _looks_ innocent enough; you might even imagine it to be a relatively healthy sandwich. Of course, in reality, the Hot Dog is barely better than junk food.','sandwich/hot-dog',NULL,NULL,54,14,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(81,'Sunscreen','In ancient Greece, olive oil was used as sunscreen; in ancient Egypt, extracts of rice, jasmine, and lupine plants. Among the nomadic, sea-going Sama-Bajau people of the Philippines, Malaysia, and Indonesia, a paste made from water weeds, rice and spices was used.\r\n\r\nSo what\'s in _this_ sunscreen? \\*shrugs\\* \'hell if I know. Smells good, though.\r\n\r\nHEY, NO EATING!','tool/sunscreen',NULL,9,NULL,0,NULL,NULL,0,0,42,NULL,NULL,0,NULL,0,1),(82,'Red Firework',NULL,'firework/red','[[\"Light\", \"firework/#/light\"]]',NULL,NULL,0,NULL,162,60,0,11,NULL,NULL,0,NULL,0,5),(83,'White Firework','Legend speaks of a firework crafted by moonbeams and wishes?? You must be thinking of a more-different firework.','firework/white','[[\"Light\", \"firework/#/light\"]]',NULL,NULL,0,NULL,163,60,0,11,NULL,NULL,0,NULL,0,5),(84,'Blue Firework',NULL,'firework/blue','[[\"Light\", \"firework/#/light\"]]',NULL,NULL,0,NULL,164,60,0,11,NULL,NULL,0,NULL,0,5),(85,'Welcome Note','👋','note/welcome','[[\"Read\", \"note/welcome/#/read\"], [\"Erase\", \"note/#/erase\"]]',NULL,NULL,0,NULL,NULL,60,0,NULL,NULL,NULL,0,NULL,0,1),(86,'Kombucha','A lightly-carbonated drink made by fermenting Sweet Black Tea.','tea/black-fermented',NULL,NULL,55,5,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(87,'Talon','Or, like, Nail, or Horn, or whatever. Don\'t get it twisted.','animal/talon',NULL,NULL,NULL,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(88,'Iron Ore','Billions of years of stellar evolution led to this iron\'s creation before you and your pets dug it up. It\'s witnessed the birth and death of stars, but, you know, it\'s cool with being turned into a sword, or whatever.','element/iron-ore',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(89,'Iron Bar',NULL,'element/iron-pure',NULL,NULL,NULL,0,NULL,NULL,0,1,NULL,NULL,NULL,0,NULL,0,1),(90,'Silver Ore',NULL,'element/silver-ore',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(91,'Silver Bar','An essential component for crafting superconductors, advanced quantum circuits, and blinged-out nests to attract potential mates.','element/silver-pure',NULL,NULL,NULL,0,NULL,NULL,0,1,NULL,NULL,3,0,NULL,0,1),(92,'Gold Ore','Did you know that \"dog lore\" is an anagram of \"gold ore\"!\r\n\r\nWhat sweet-sweet dog facts is gold ore hiding from us, huh?!\r\n\r\nAnd, I mean, _yes_, \"door gel\" and \"leg odor\" are _also_ anagrams of \"gold ore\"! But don\'t worry about those ones! (Especially the \"leg odor\" one... that one\'s just... weird.)','element/gold-ore',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(93,'Gold Bar',NULL,'element/gold-pure',NULL,NULL,NULL,0,NULL,NULL,0,1,NULL,NULL,24,0,NULL,0,1),(94,'Yellow Dye','The label clearly states this can be used to dye things yellow. Like buckets. Or idols that need to look gold for completely legitimate reasons that don\'t require further explanation...','resource/dye-yellow',NULL,NULL,NULL,0,NULL,NULL,0,1,NULL,NULL,NULL,0,NULL,0,1),(95,'Green Dye',NULL,'resource/dye-green',NULL,NULL,NULL,0,NULL,NULL,0,1,NULL,NULL,NULL,0,NULL,0,1),(96,'Piece of Cetgueli\'s Map','You\'ve no doubt heard at least one story about the Duke of Cetgueli\'s many exploits: the time he cut himself with an Ivy Dagger during a fancy dinner at his own estate; his failed attempt to negotiate with a sprig of Deathmint; how he \"inspired\" the famous inventor Isabel to create the now-common kitchen Jellier. But one story you may not have heard is that of his life of piracy as a youth.\r\n\r\nIt\'s said that starting at the age of 15, he became a cabin boy, and stole and hid untold quantities of treasure from the many pirate captains he served with, moving from ship to ship without ever getting caught. After he served aboard nearly ever ship he could, he retired at the age of 22, and purchased the entire Cetgueli province outright (supposedly his first, and last, truly-intelligent act).\r\n\r\nThis torn piece of map suggests that the story may be true. Perhaps, if you could _combine_ enough pieces at once, you could reconstruct the full thing...','map/cetgueli-piece',NULL,NULL,NULL,0,NULL,NULL,120,0,NULL,NULL,NULL,0,NULL,0,1),(97,'Little Strongbox','Hm! It appears that this box is locked with an Iron Lock. Well, as we all know, any Iron Lock can be opened with any Iron Key. (Everyone knows _that_!)','box/strong-little','[[\"Unlock (with Iron Key)\", \"box/little-strongbox/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(98,'Very Strongbox','This troublesome box is locked with a Silver Lock!','box/strong-very','[[\"Unlock (with Silver Key)\", \"box/very-strongbox/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(99,'Outrageously Strongbox','I hope you weren\'t going to try and force this strongbox open: it\'s definitely way stronger than you are. Like _crazy_ strong! I\'m afraid you\'ll just have to find a Gold Key to unlock it with.','box/strong-outrageously','[[\"Unlock (with Gold Key)\", \"box/outrageously-strongbox/#/open\"]]',NULL,NULL,0,NULL,NULL,0,0,16,NULL,NULL,0,NULL,0,1),(100,'Cetgueli\'s Treasure Map',NULL,'map/cetgueli',NULL,6,NULL,0,NULL,NULL,600,0,NULL,NULL,NULL,0,NULL,0,20),(101,'Iron Key',NULL,'key/iron',NULL,NULL,NULL,0,NULL,NULL,0,2,NULL,NULL,NULL,0,NULL,0,1),(102,'Silver Key',NULL,'key/silver',NULL,NULL,NULL,0,NULL,NULL,0,2,NULL,NULL,2,0,NULL,0,1),(103,'Gold Key','What good is a gold trophy? A Gold _Key_ will reveal yet more treasures... and is more portable!','key/gold',NULL,NULL,NULL,0,NULL,NULL,0,2,NULL,NULL,25,0,NULL,0,1),(104,'Rusty Rapier','This blade has seen more seawater than combat.','tool/sword/rapier-rusty',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(105,'Rusty Blunderbuss','Every rusted spot is a remnant of an adventure; every dent, a story of close encounters and narrow escapes on stormy nights and treacherous shores.\n\n_Buuuuuuut_... it\'d probably be more useful if it was repaired. Sorry/not-sorry, treacherous shores: your story was givin\' me nightmares, anyway!','tool/gun/blunderbuss-rusty',NULL,NULL,NULL,0,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(106,'Blunderbuss','Pew, pew!','tool/gun/blunderbuss',NULL,91,NULL,0,NULL,NULL,0,2,NULL,NULL,NULL,0,NULL,0,1),(107,'Rapier',NULL,'tool/sword/rapier',NULL,90,NULL,0,NULL,NULL,0,2,NULL,NULL,NULL,0,NULL,0,1),(108,'Quintessence','A bit of the stuff that forms the very fabric of reality, made solid.','resource/quintessence',NULL,NULL,NULL,0,NULL,NULL,300,0,NULL,NULL,NULL,0,NULL,0,1),(109,'Baking Powder','Baking _Soda_, Baking _Powder_... what\'s the dang difference, anyway?!\r\n\r\nOh, uh, it says here that Baking Powder is a combination of Baking Soda, and some acidic powder, usually Cream of Tartar.\r\n\r\nWELL THEN.\r\n\r\nThere you go.','ingredient/baking-powder',NULL,NULL,NULL,1,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(110,'World\'s Best Sugar Cookie','I mean, that\'s what the recipe I found on a website said. Unless... you don\'t think a website would _lie_ to me, would it??','dessert/cookie-sugar',NULL,NULL,56,5,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(111,'Yeast','I mean... you _could_ just open a packet and pour it into your mouth. I guess. I mean, _I_ wouldn\'t, but, you know: you do you.','fungus/yeast-bakers',NULL,NULL,57,2,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(112,'Slice of Bread','No Peanut Butter? No problem! Make a nice Grilled Cheese by buttering (or oiling) up a pan, and frying up some cheese on a single Slice of Bread.\r\n\r\nDunno why only one slice is required. That\'s just the magic of Poppy Seed Pets, I guess.','bread/plain-slice',NULL,NULL,58,4,NULL,NULL,15,0,NULL,NULL,NULL,0,NULL,0,1),(113,'Plain Yogurt',NULL,'yogurt/plain',NULL,NULL,59,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(114,'Painted Fishing Rod','It\'s, um, stealthier this way.','tool/fishing-rod/crooked-painted',NULL,7,NULL,0,NULL,NULL,315,5,NULL,NULL,NULL,0,NULL,0,10),(115,'Meringue','So light and airy, it\'s like eating a cloud. A delicious, sugary, oddly-crunchy cloud.','dessert/meringue',NULL,NULL,60,5,NULL,13,0,0,NULL,NULL,NULL,0,NULL,0,1),(116,'Cocoa Powder','Contains trace amounts of theobromine, a mood-lifting compound. Also contains not-so-trace amounts of deliciousness, a different kind of mood-lifting compound.','ingredient/cocoa-powder',NULL,NULL,NULL,4,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(117,'Chocolate Meringue','It looks _just_ like Chocolate Meringue, and _nothing_ else, and I\'LL ACCEPT NO SUGGESTIONS TO THE CONTRARY.\r\n\r\nOkay, so it looks like poop.\r\n\r\nBut it\'s super-tasty, I super-promise.','dessert/meringue-chocolate',NULL,NULL,61,7,NULL,12,0,0,NULL,NULL,NULL,0,NULL,0,1),(118,'Champignon','Ever notice how mushrooms pop up in circles sometimes? Like they\'re trying to tell us something about the spaces between spaces. This staff seems to whisper similar secrets - though mostly about where to find more sparkly magic stuff.','tool/wand/champignon',NULL,8,NULL,0,NULL,NULL,600,5,NULL,NULL,NULL,0,NULL,0,10),(119,'Charcoal','Perfect for smelting, grilling, and making a mess! Wow! So versatile!','resource/charcoal',NULL,NULL,NULL,3,NULL,NULL,180,0,NULL,NULL,NULL,0,NULL,0,1),(120,'Grilled Fish','Kissed by the flame,\nseasoned by the sea.\nNature\'s culinary\npoetry.','animal/meat/fish-grilled',NULL,NULL,62,15,NULL,NULL,0,0,NULL,NULL,NULL,0,NULL,0,1),(121,'Pectin','Despite how it sounds, pec