DROP TABLE IF EXISTS `item_food`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `item_food` (
  `id` int NOT NULL AUTO_INCREMENT,
  `food` int NOT NULL,
  `love` int NOT NULL,
  `junk` int NOT NULL,
  `alcohol` int NOT NULL,
  `earthy` int NOT NULL,
  `fruity` int NOT NULL,
  `tannic` int NOT NULL,
  `spicy` int NOT NULL,
  `creamy` int NOT NULL,
  `meaty` int NOT NULL,
  `planty` int NOT NULL,
  `fishy` int NOT NULL,
  `floral` int NOT NULL,
  `fatty` int NOT NULL,
  `oniony` int NOT NULL,
  `chemically` int NOT NULL,
  `caffeine` int NOT NULL,
  `psychedelic` int NOT NULL,
  `granted_skill` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `chance_for_bonus_item` int DEFAULT NULL,
  `random_flavor` int NOT NULL,
  `contains_tentacles` tinyint(1) NOT NULL,
  `granted_status_effect` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `granted_status_effect_duration` int DEFAULT NULL,
  `is_candy` tinyint(1) NOT NULL,
  `leftovers_id` int DEFAULT NULL,
  `bonus_item_group_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `is_candy_idx` (`is_candy`),
