INSERT INTO `merit` VALUES (1,'Eidetic Memory','%pet.name% will never forget. Activities that challenge memory will be no problem for them.'),(2,'Black Hole Tum','%pet.name% will be able to store a bit more food in their stomach. Oh: and will poop Dark Matter???'),(3,'Lucky','%pet.name% will stumble upon fortune more often than most! Lucky~!'),(4,'Moon-bound','%pet.name% will be physically stronger near a full moon, but slightly weaker on new moons.'),(5,'Natural Channel','%pet.name% will be able to slip into and out of the Umbra at will - sometimes accidentally!'),(6,'No Shadow; No Reflection','%pet.name% will no longer cast a shadow, and will no longer be visible in reflective surfaces! (Creepy... but occasionally useful!)'),(7,'Soothing Voice','%pet.name%\'s voice will calm all who hear it...'),(8,'Spirit Companion','%pet.name% will attract a friendly spirit companion!'),(9,'Protocol 7','%pet.name% will be able to access Project-E directly, without the need for a device.'),(10,'Introspective','%pet.name% will know clearly what they want in their relationships... and so will you!'),(11,'Volagamy','%pet.name% will be able to become pregnant or lay eggs, and you\'ll be able to turn this ability on or off at will.'),(12,'Behatted','%pet.name% will be able to wear hats!'),(13,'Mind Over Matter','%pet.name% chose to start by focusing on their intelligence, rather than their strength.'),(14,'Matter Over Mind','%pet.name% chose to start by focusing on their strength, rather than their intelligence.'),(15,'Moderation','%pet.name% chose to start by taking care of both their body, and their mind.'),(16,'Force of Will','%pet.name% has ultimately decided that nothing is impossible with a strong mind.'),(17,'Force of Nature','%pet.name% has ultimately decided that nothing is impossible with a strong physique.'),(18,'Balance','%pet.name% has ultimately decided that the body and the mind are equally important.'),(19,'Burps Moths','When fed, %pet.name% may burp up a Moth...'),(20,'Friend of the World','%pet.name% believes in friendship! They don\'t like to end relationships, and will agree to relationship changes instead of breaking up.'),(21,'Gourmand','%pet.name% has a slightly-larger stomach, and may have... _different_ interactions with creatures made of food.'),(22,'Spectral','%pet.name% is... not _entirely_ opaque...'),(23,'Prehensile Tongue','Remember all those times you thought \"man, I wish I had a third arm\"? %pet.name% has never had to think that.'),(24,'Lolligovore','%pet.name% really likes eating Tentacles.'),(25,'Hyperchromatic','%pet.name%\'s colors shift and change over time, sometimes abruptly.'),(26,'Dreamwalker','%pet.name% will have vivid dreams which they can pull objects out of!'),(27,'Gregarious','%pet.name% will join more groups than most.'),(28,'Sheds','%pet.name% sheds.'),(29,'Darkvision','%pet.name% can see in the dark without the help of a tool.'),(30,'Mirrored','%pet.name% prefers looking the _other_ direction...'),(31,'Never Embarrassed','%pet.name%\'s Esteem will gravitate towards a positive value, rather than a neutral one.'),(32,'Everlasting Love','%pet.name%\'s Love will gravitate towards a positive value, rather than a neutral one.'),(33,'Nothing to Fear','%pet.name%\'s Safety will gravitate towards a positive value, rather than a neutral one.'),(34,'Inverted','%pet.name%\'s colors are inverted!'),(35,'Very Inverted','Not only are %pet.name%\'s colors inverted, but so are the colors of their hat and tool!'),(36,'Wondrous Strength','%pet.name% has been blessed with magical strength!'),(37,'Wondrous Stamina','%pet.name% has been blessed with magical endurance!'),(38,'Wondrous Dexterity','%pet.name% has been blessed with magically-nimble hands! (Or... wings, or tentacles, or whatever...)'),(39,'Wondrous Perception','%pet.name% has been blessed with magical perception!'),(40,'Wondrous Intelligence','%pet.name% has been blessed with a magical intellect!'),(41,'Eternal','This pet was brought to life by a Philosopher\'s Stone, and can never die! Then again, none of the pets in Poppy Seed Pets die... Oh: but they do also get +1 to all their stats, so that\'s neat!'),(42,'Affectionless','%pet.name% cannot form relationships, or gain Affection (ex: from petting, feeding foods containing its favorite flavor, etc).'),(43,'Sága Saga','When %pet.name% gains its 5th point in any skill, it will turn into a Skill Scroll for that skill; only its ghost will remain...'),(44,'Luminary Essence','%pet.name% gets +1 Arcana, and attracts more bugs than other pets.'),(45,'Silverblood','%pet.name% is immune to werecreature bites, and is naturally-talented at working with Silver Ore and Silver Bars.'),(46,'Green Thumb','%pet.name% is great with plants. +1 Nature, and gets extra items when assigned as a helper at the Greenhouse or Beehive.'),(47,'Gecko Fingers','%pet.name% is a natural climber! +2 Climbing.'),(48,'Shock-resistant','%pet.name% is immune to most electrical attacks, and the random discharges that can happen when crafting some electronics.'),(49,'Way of the Empty Hand','%pet.name% is an excellent unarmed fighter! +5 Brawl when not using a tool, or when using a tool that provides no Brawl bonus.'),(50,'Athena\'s Gifts','%pet.name% is blessed by the goddess of crafts - Athena - and will sometimes receive a Handicrafts Supply Box out of nowhere!'),(51,'Iron Stomach','%pet.name%\'s stomach resists toxins. Psychedelic, alcoholic, and caffeinated food and drink are only half as poisonous for this pet.'),(52,'Celestial Choruser','%pet.name% sings for the cosmos. Whenever they get an item from the [Outer Space](/poppyopedia/item?filter.itemGroup=Outer%20Space) item group, they also get a Music Note.'),(53,'Doppel Gene','%pet.name% always gives birth to twins! (If they lay eggs, the eggs have twins inside.)'),(54,'Fairy Godmother','%pet.name% has a fairy godmother. They\'ll stop by to check in from time to time.'),(55,'Rumpelstiltskin\'s Curse','When %pet.name% collects wheat, it\'s turned into gold... and vice-versa!'),(56,'Bigger Lunchbox','This pet\'s lunchbox is bigger! Only on the inside, for some reason, but that\'s where you put the food, anyway, so... yeah! +1 lunchbox capacity!'),(57,'Blush of Life','%pet.name% will not lose their color when Bitten (by a Vampire).'),(58,'Caching','%pet.name% has secret caches of food hidden around the island, and may dig them up when hungry!'),(60,'Ichthyastra','A third of the Fish that %pet.name% acquires will have a random spice applied, however %pet.name% can never again seek the Vesica Hydrargyrum.'),(61,'Metatron\'s Touch','When %pet.name% makes something with Firestone, a Rock is leftover, however %pet.name% can never again seek Metatron\'s Fire.'),(62,'Manxome','If %pet.name% has less Dexterity than Stamina, it gets +1 Dexterity, otherwise it gets +1 Stamina. Regardless, %pet.name% can never again seek Earth\'s Egg.'),(63,'Lightning Reins','Whenever %pet.name% collects Lightning in a Bottle, it also gets Quintessence, however %pet.name% can never again seek the Merkaba of Air.'),(64,'Mortars and Pestles','%pet.name% learned something fundamental about how mortals and pestles work? I guess? Whatever the case: +1 Mining.');
/*!40000 ALTER TABLE `merit` ENABLE KEYS */;
UNLOCK TABLES;

