LOCK TABLES `monthly_story_adventure` WRITE;
/*!40000 ALTER TABLE `monthly_story_adventure` DISABLE KEYS */;
INSERT INTO `monthly_story_adventure` VALUES (1,'The Pirates of Dragonhead Island','\"Before their fall, the Shalurians were said to be technologically and spiritually advanced; now their kingdom lies in ruin, occupied by those who do not find the laws of civilization to their liking.\n\nWhat reason could our Lord have for sending us _here_?\"',1,2022,7,0),(2,'What Lives in the Dark','While digging, the townsfolk discovered a cave. Several people have gone in to investigate, but none have returned. Scared, the people are calling upon their god for the safe return of their loved ones...',2,2022,8,1),(3,'The Errant Prince','Abamātu - a local sea god - has asked our lord a favor: it is his son\'s birthday, and Abamātu wishes to ensure that his prince-son makes it safely home. We are to escort him.',3,2022,9,0),(4,'A New Goddess','The Land of the Dead has been in a state of turmoil ever since its god - Enmesharra - was slain. With no heirs, there have been many wars fought over who should rule the underworld. Recently, however, a new goddess claimed the throne, and there are few that oppose her rule. The wars in the Land of the Dead may finally be over, and we have been sent as emissaries of our lord to establish a relationship with its new goddess...',4,2022,10,0),(5,'REMIX','You\'ve run enough prefab scenarios for your pets... time to mix it up a bit!',0,0,0,0);
/*!40000 ALTER TABLE `monthly_story_adventure` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `monthly_story_adventure_step`
