DROP TABLE IF EXISTS `monthly_story_adventure_step`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `monthly_story_adventure_step` (
  `id` int NOT NULL AUTO_INCREMENT,
  `adventure_id` int NOT NULL,
  `aura_id` int DEFAULT NULL,
  `title` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `step` int NOT NULL,
  `previous_step` int DEFAULT NULL,
  `x` double NOT NULL,
  `y` double NOT NULL,
  `min_pets` int NOT NULL,
  `max_pets` int NOT NULL,
  `narrative` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `treasure` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pin_override` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IDX_2D91EBCA55CF40F9` (`adventure_id`),
  KEY `IDX_2D91EBCA72CA3BB6` (`aura_id`),
  CONSTRAINT `FK_2D91EBCA55CF40F9` FOREIGN KEY (`adventure_id`) REFERENCES `monthly_story_adventure` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `FK_2D91EBCA72CA3BB6` FOREIGN KEY (`aura_id`) REFERENCES `enchantment` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=118 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
