  `spirit_companion_id` int DEFAULT NULL,
  `last_park_event` date DEFAULT NULL COMMENT '(DC2Type:date_immutable)',
  `park_event_type` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `park_event_order` int NOT NULL,
  `caffeine` int NOT NULL,
