  `poison` int NOT NULL,
  `extroverted` smallint NOT NULL,
  `sex_drive` smallint NOT NULL,
  `pregnancy_id` int DEFAULT NULL,
  `mom_id` int DEFAULT NULL,
  `dad_id` int DEFAULT NULL,
  `is_fertile` tinyint(1) NOT NULL,
  `hat_id` int DEFAULT NULL,
  `costume` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `love_language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_grandparent` tinyint(1) NOT NULL,
  `claimed_grandparent_merit` tinyint(1) NOT NULL,
