  `self_reflection_point` smallint NOT NULL,
  `scale` smallint NOT NULL,
  `activity_personality` int NOT NULL,
  `location` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `affection_expressions` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `renaming_charges` smallint NOT NULL,
  `location_move_date` datetime DEFAULT NULL COMMENT '(DC2Type:datetime_immutable)',
  `spirit_dad_id` int DEFAULT NULL,
  `lunchbox_index` int NOT NULL,
